/**
 * Simulated notification adapters for different channels.
 * In a real app, these would call SendGrid, Twilio, etc.
 */

export interface NotificationPayload {
    to: string;
    subject?: string;
    body: string;
    metadata?: any;
}

export const EmailAdapter = {
    send: async (payload: NotificationPayload) => {
        console.log(`[SIMULATED EMAIL] To: ${payload.to} | Subject: ${payload.subject} | Body: ${payload.body}`);
        return { success: true, message_id: `sim-email-${Math.random().toString(36).substr(2, 9)}` };
    }
};

export const SmsAdapter = {
    send: async (payload: NotificationPayload) => {
        console.log(`[SIMULATED SMS] To: ${payload.to} | Body: ${payload.body}`);
        return { success: true, message_id: `sim-sms-${Math.random().toString(36).substr(2, 9)}` };
    }
};

export const WhatsAppAdapter = {
    send: async (payload: NotificationPayload) => {
        console.log(`[SIMULATED WHATSAPP] To: ${payload.to} | Body: ${payload.body}`);
        return { success: true, message_id: `sim-wa-${Math.random().toString(36).substr(2, 9)}` };
    }
};

export const TelegramAdapter = {
    send: async (payload: NotificationPayload) => {
        console.log(`[SIMULATED TELEGRAM] To: ${payload.to} | Body: ${payload.body}`);
        return { success: true, message_id: `sim-tg-${Math.random().toString(36).substr(2, 9)}` };
    }
};

export const getTemplates = (data: any) => ({
    APPOINTMENT_CONFIRMED: {
        subject: 'Cita Confirmada - Taller Denver',
        body: `Hola ${data.name}, tu cita para el ${data.date} ha sido confirmada.`
    },
    DIAGNOSIS_READY: {
        subject: 'Diagnóstico Listo - Vehículo ${data.vehicle}',
        body: `Hola ${data.name}, el diagnóstico para tu ${data.vehicle} ya está disponible en la app.`
    },
    QUOTE_SENT: {
        subject: 'Presupuesto Disponible - Taller Denver',
        body: `Hemos generado un presupuesto para tu servicio. Por favor revísalo y apruébalo para comenzar.`
    },
    QUOTE_APPROVED: {
        subject: 'Presupuesto Aprobado',
        body: `¡Gracias! Hemos recibido tu aprobación. El técnico comenzará a trabajar pronto.`
    },
    QUOTE_DECLINED: {
        subject: 'Presupuesto Rechazado',
        body: `Lamentamos que no desees continuar con el servicio. Háznoslo saber si podemos ayudarte en algo más.`
    }
});

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Badge } from '../../components/ui/Badge';
import {
    Plus, Trash2, Power, PowerOff,
    Settings2, Tags, Search
} from 'lucide-react';
import { supabase } from '../../lib/supabase';

export function AdminCatalogPage() {
    const [services, setServices] = useState<any[]>([]);
    const [tags, setTags] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    async function loadData() {
        setLoading(true);
        try {
            const { data: srvData } = await supabase.from('service_catalog').select('*').order('name');
            const { data: tagData } = await supabase.from('symptom_tags').select('*').order('label');
            setServices(srvData || []);
            setTags(tagData || []);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    }

    async function toggleService(id: string, current: boolean) {
        await supabase.from('service_catalog').update({ active: !current }).eq('id', id);
        loadData();
    }

    async function deleteTag(id: string) {
        if (!confirm('¿Eliminar esta etiqueta?')) return;
        await supabase.from('symptom_tags').delete().eq('id', id);
        loadData();
    }

    async function addService() {
        const name = prompt('Nombre del servicio:');
        if (!name) return;
        const category = prompt('Categoría (MECHANICAL, ELECTRICAL, etc):', 'MECHANICAL');
        const price = prompt('Precio base:', '100');

        await supabase.from('service_catalog').insert({
            name,
            category,
            base_price: parseFloat(price || '0'),
            active: true
        });
        loadData();
    }

    async function addTag() {
        const label = prompt('Nombre del síntoma:');
        if (!label) return;
        const code = label.toUpperCase().replace(/\s+/g, '_');
        const severity = prompt('Severidad (LOW/MED/HIGH/CRITICAL):', 'LOW');

        await supabase.from('symptom_tags').insert({
            label,
            code,
            severity,
            active: true
        });
        loadData();
    }

    const filteredServices = services.filter(s =>
        s.name.toLowerCase().includes(search.toLowerCase()) ||
        s.category.toLowerCase().includes(search.toLowerCase())
    );

    if (loading) return <div className="p-10 text-center animate-pulse text-indigo-600 font-bold">Cargando Catálogo...</div>;

    return (
        <div className="space-y-8 pb-20 animate-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 flex items-center gap-2">
                        <Settings2 className="text-indigo-600" /> Catálogo de Servicios
                    </h1>
                    <p className="text-slate-500 font-medium">Gestiona la oferta de servicios y etiquetas de síntomas.</p>
                </div>
                <div className="flex gap-2">
                    <Button onClick={addService} className="bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100 shadow-lg">
                        <Plus size={18} className="mr-2" /> Nuevo Servicio
                    </Button>
                    <Button onClick={addTag} variant="outline" className="border-indigo-200 text-indigo-600">
                        <Plus size={18} className="mr-2" /> Nueva Etiqueta
                    </Button>
                </div>
            </div>

            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <Input
                    placeholder="Buscar servicios por nombre o categoría..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="pl-10 h-12 bg-white border-slate-200 shadow-sm focus:ring-indigo-500 rounded-xl"
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Services Section */}
                <div className="space-y-4">
                    <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 px-1">
                        Servicios Activos ({filteredServices.length})
                    </h2>
                    <div className="grid gap-3">
                        {filteredServices.map(service => (
                            <Card key={service.id} className={`overflow-hidden transition-all hover:translate-x-1 ${!service.active ? 'opacity-60 grayscale bg-slate-50 border-dashed' : 'bg-white shadow-sm border-indigo-100'}`}>
                                <CardContent className="p-4 flex items-center justify-between">
                                    <div className="flex gap-4 items-center">
                                        <div className={`p-3 rounded-xl ${service.active ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-200 text-slate-500'}`}>
                                            <Settings2 size={20} />
                                        </div>
                                        <div>
                                            <div className="flex items-center gap-2">
                                                <h3 className="font-bold text-slate-900">{service.name}</h3>
                                                <Badge variant="outline" className="text-[10px] py-0">{service.category}</Badge>
                                            </div>
                                            <p className="text-sm font-bold text-indigo-600 mt-0.5">${service.base_price}</p>
                                        </div>
                                    </div>
                                    <div className="flex gap-1">
                                        <Button
                                            size="icon"
                                            variant="ghost"
                                            onClick={() => toggleService(service.id, service.active)}
                                            className={service.active ? 'text-green-600 hover:bg-green-50' : 'text-slate-400 hover:bg-slate-100'}
                                            title={service.active ? 'Desactivar' : 'Activar'}
                                        >
                                            {service.active ? <Power size={18} /> : <PowerOff size={18} />}
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                </div>

                {/* Tags Section */}
                <div className="space-y-4">
                    <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 px-1">
                        Etiquetas de Síntomas <Tags size={18} className="text-amber-500" />
                    </h2>
                    <Card className="bg-white shadow-lg border-amber-100 rounded-2xl">
                        <CardContent className="p-6">
                            <div className="flex flex-wrap gap-2">
                                {tags.map(tag => (
                                    <div
                                        key={tag.id}
                                        className="group relative flex items-center gap-2 px-3 py-1.5 bg-slate-50 border border-slate-200 rounded-full hover:border-amber-300 hover:bg-amber-50 transition-all"
                                    >
                                        <span className={`w-2 h-2 rounded-full ${tag.severity === 'CRITICAL' ? 'bg-red-500' :
                                                tag.severity === 'HIGH' ? 'bg-orange-500' :
                                                    tag.severity === 'MED' ? 'bg-amber-500' : 'bg-green-500'
                                            }`} />
                                        <span className="text-sm font-bold text-slate-700">{tag.label}</span>
                                        <button
                                            onClick={() => deleteTag(tag.id)}
                                            className="opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-600 transition-opacity ml-1"
                                        >
                                            <Trash2 size={12} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                            {tags.length === 0 && (
                                <div className="text-center py-6 text-slate-400 italic text-sm">
                                    No hay etiquetas configuradas.
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import {
    Settings, MapPin, DollarSign,
    Save, Plus, Trash2, Truck
} from 'lucide-react';
import { supabase } from '../../lib/supabase';

export function AdminConfigPage() {
    const [config, setConfig] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        loadConfig();
    }, []);

    async function loadConfig() {
        const { data } = await supabase.from('app_config').select('*').single();
        if (data) setConfig(data);
        setLoading(false);
    }

    async function handleSave() {
        setSaving(true);
        try {
            const { error } = await supabase
                .from('app_config')
                .update({
                    service_hub_lat: parseFloat(config.service_hub_lat),
                    service_hub_lng: parseFloat(config.service_hub_lng),
                    visit_fee: parseFloat(config.visit_fee),
                    distance_ranges: config.distance_ranges
                })
                .eq('id', config.id);

            if (error) alert(error.message);
            else alert('Configuración guardada correctamente.');
        } catch (err) {
            console.error(err);
        } finally {
            setSaving(false);
        }
    }

    function addRange() {
        const ranges = [...(config.distance_ranges || [])];
        ranges.push({ min: 0, max: 0, surcharge: 0 });
        setConfig({ ...config, distance_ranges: ranges });
    }

    function removeRange(index: number) {
        const ranges = config.distance_ranges.filter((_: any, i: number) => i !== index);
        setConfig({ ...config, distance_ranges: ranges });
    }

    function updateRange(index: number, field: string, value: string) {
        const ranges = [...config.distance_ranges];
        ranges[index] = { ...ranges[index], [field]: parseFloat(value || '0') };
        setConfig({ ...config, distance_ranges: ranges });
    }

    if (loading) return <div className="p-10 text-center animate-pulse text-indigo-600 font-bold italic underline">Cargando Configuración Global...</div>;

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-in">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 flex items-center gap-2">
                        <Settings className="text-indigo-600 animate-spin-slow" /> Configuración Global
                    </h1>
                    <p className="text-slate-500 font-medium">Controla los parámetros operativos y precios del sistema.</p>
                </div>
                <Button onClick={handleSave} disabled={saving} className="bg-indigo-600 hover:bg-indigo-700 shadow-xl shadow-indigo-100 px-8 py-6 rounded-2xl">
                    <Save size={18} className="mr-2" /> {saving ? 'Guardando...' : 'GUARDAR CAMBIOS'}
                </Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Hub Location */}
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden">
                    <CardHeader className="bg-slate-50 border-b border-slate-100">
                        <CardTitle className="text-sm font-bold flex items-center gap-2 uppercase tracking-wide text-slate-500">
                            <MapPin size={16} className="text-red-500" /> Ubicación del Hub Central
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="p-6 space-y-4">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-tighter ml-1">Latitud</label>
                            <Input
                                type="number"
                                value={config.service_hub_lat}
                                onChange={(e) => setConfig({ ...config, service_hub_lat: e.target.value })}
                                className="h-12 text-sm font-medium border-slate-100 focus:ring-red-500 rounded-xl"
                            />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-tighter ml-1">Longitud</label>
                            <Input
                                type="number"
                                value={config.service_hub_lng}
                                onChange={(e) => setConfig({ ...config, service_hub_lng: e.target.value })}
                                className="h-12 text-sm font-medium border-slate-100 focus:ring-red-500 rounded-xl"
                            />
                        </div>
                        <p className="text-[10px] text-slate-400 font-medium italic mt-2 animate-pulse">
                            * Se usa para calcular distancias automáticas en futuros módulos.
                        </p>
                    </CardContent>
                </Card>

                {/* Base Pricing */}
                <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden">
                    <CardHeader className="bg-slate-50 border-b border-slate-100">
                        <CardTitle className="text-sm font-bold flex items-center gap-2 uppercase tracking-wide text-slate-500">
                            <DollarSign size={16} className="text-green-500" /> Tarifas de Servicio
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="p-6 space-y-4">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-tighter ml-1">Cuota de Visita Base (USD)</label>
                            <Input
                                type="number"
                                value={config.visit_fee}
                                onChange={(e) => setConfig({ ...config, visit_fee: e.target.value })}
                                className="h-12 text-lg font-black text-green-600 border-slate-100 focus:ring-green-500 rounded-xl"
                            />
                        </div>
                        <div className="p-4 bg-green-50 border border-green-100 rounded-2xl flex items-center gap-3">
                            <Truck className="text-green-600" size={24} />
                            <p className="text-[11px] text-green-700 font-bold leading-tight">
                                Este valor se suma a cada cita y puede descontarse al aprobar cotizaciones.
                            </p>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Distance Pricing Ranges */}
            <Card className="bg-white border-slate-200 shadow-sm rounded-3xl overflow-hidden border-2 border-dashed border-indigo-100">
                <CardHeader className="bg-indigo-50 border-b border-indigo-100 flex flex-row items-center justify-between">
                    <CardTitle className="text-sm font-bold flex items-center gap-2 uppercase tracking-wide text-indigo-600">
                        <Truck size={16} /> Rangos de Cobro por Distancia
                    </CardTitle>
                    <Button size="sm" onClick={addRange} className="bg-white text-indigo-600 hover:bg-slate-50 border border-indigo-200 h-8 font-black text-[10px]">
                        <Plus size={14} className="mr-1" /> AGREGAR RANGO
                    </Button>
                </CardHeader>
                <CardContent className="p-6">
                    <div className="space-y-3">
                        <div className="grid grid-cols-4 gap-4 px-2 mb-2">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Min Millas</span>
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Max Millas</span>
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Recargo ($)</span>
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Acciones</span>
                        </div>
                        {config.distance_ranges?.map((range: any, idx: number) => (
                            <div key={idx} className="grid grid-cols-4 gap-4 bg-slate-50 p-2 rounded-xl group hover:bg-indigo-50/30 transition-colors">
                                <Input
                                    type="number"
                                    value={range.min}
                                    onChange={(e) => updateRange(idx, 'min', e.target.value)}
                                    className="h-10 text-center font-bold text-xs border-indigo-50 bg-white"
                                />
                                <Input
                                    type="number"
                                    value={range.max}
                                    onChange={(e) => updateRange(idx, 'max', e.target.value)}
                                    className="h-10 text-center font-bold text-xs border-indigo-50 bg-white"
                                />
                                <Input
                                    type="number"
                                    value={range.surcharge}
                                    onChange={(e) => updateRange(idx, 'surcharge', e.target.value)}
                                    className="h-10 text-center font-black text-xs text-indigo-600 border-indigo-50 bg-white"
                                />
                                <div className="flex items-center justify-center">
                                    <Button
                                        size="icon"
                                        variant="ghost"
                                        onClick={() => removeRange(idx)}
                                        className="h-10 w-10 text-red-300 hover:text-red-500 hover:bg-red-50 transition-all"
                                    >
                                        <Trash2 size={16} />
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

