import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { Badge } from '../../components/ui/Badge';
import { Input } from '../../components/ui/Input';
import { Button } from '../../components/ui/Button';
import {
    FileText, Search, Filter, Calendar,
    ChevronRight, Eye, User, CarFront
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { Link } from 'react-router-dom';

export function AdminRequestsPage() {
    const [requests, setRequests] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [filterStatus, setFilterStatus] = useState('ALL');
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        loadRequests();
    }, [filterStatus]);

    async function loadRequests() {
        setLoading(true);
        let query = supabase
            .from('service_requests')
            .select('*, profiles(first_name, last_name, email), vehicles(make, model, year)')
            .order('created_at', { ascending: false });

        if (filterStatus !== 'ALL') {
            query = query.eq('status', filterStatus);
        }

        const { data } = await query;
        setRequests(data || []);
        setLoading(false);
    }

    const filtered = requests.filter(r =>
        r.profiles?.first_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.profiles?.last_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.vehicles?.make.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const statuses = ['ALL', 'DRAFT', 'SCHEDULED', 'IN_PROGRESS', 'DIAGNOSED', 'QUOTED', 'APPROVED', 'COMPLETED', 'DECLINED', 'CANCELED'];

    if (loading) return <div className="p-10 text-center animate-pulse text-indigo-600 font-bold italic">Cargando todas las solicitudes...</div>;

    return (
        <div className="space-y-6 pb-20 animate-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 px-1">
                <div>
                    <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 flex items-center gap-2">
                        <FileText className="text-indigo-600" /> Historial de Solicitudes
                    </h1>
                    <p className="text-slate-500 font-medium">Gestión integral de todos los servicios del taller.</p>
                </div>
            </div>

            <Card className="bg-white border-slate-200 shadow-xl shadow-slate-100 rounded-3xl overflow-hidden">
                <CardHeader className="bg-slate-50/50 border-b border-slate-100 flex flex-col md:flex-row items-center gap-4 py-6">
                    <div className="relative flex-1 w-full">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <Input
                            placeholder="Buscar por cliente o vehículo..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-12 h-12 border-slate-100 focus:ring-indigo-500 bg-white shadow-sm rounded-2xl"
                        />
                    </div>
                    <div className="flex items-center gap-2 w-full md:w-auto">
                        <Filter className="text-slate-400 hidden sm:block" size={18} />
                        <select
                            className="h-12 border-slate-100 rounded-2xl px-4 text-xs font-black uppercase tracking-tight bg-white focus:ring-indigo-500 w-full"
                            value={filterStatus}
                            onChange={(e) => setFilterStatus(e.target.value)}
                        >
                            {statuses.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                    </div>
                </CardHeader>
                <CardContent className="p-0">
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-slate-50">
                                    <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">CLIENTE</th>
                                    <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">VEHÍCULO</th>
                                    <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">ESTADO</th>
                                    <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">FECHA CREACIÓN</th>
                                    <th className="px-6 py-4 text-right border-b border-slate-100">ACCIONES</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {filtered.map(req => (
                                    <tr key={req.id} className="hover:bg-indigo-50/30 transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-black text-[10px]">
                                                    {req.profiles?.first_name[0]}{req.profiles?.last_name[0]}
                                                </div>
                                                <div className="space-y-0.5">
                                                    <p className="text-sm font-bold text-slate-900 leading-none">{req.profiles?.first_name} {req.profiles?.last_name}</p>
                                                    <p className="text-[10px] text-slate-400 font-medium">{req.profiles?.email}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-2">
                                                <CarFront size={14} className="text-slate-400" />
                                                <span className="text-xs font-bold text-slate-700">{req.vehicles?.year} {req.vehicles?.make} {req.vehicles?.model}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <Badge className={`h-5 text-[9px] font-black tracking-tighter uppercase px-2 py-0 ${req.status === 'COMPLETED' ? 'bg-green-500' :
                                                req.status === 'DECLINED' ? 'bg-red-500' :
                                                    req.status === 'APPROVED' ? 'bg-blue-600' :
                                                        req.status === 'QUOTED' ? 'bg-amber-500' : 'bg-slate-400'
                                                }`}>
                                                {req.status}
                                            </Badge>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-2 text-slate-500">
                                                <Calendar size={13} />
                                                <span className="text-xs font-medium">{new Date(req.created_at).toLocaleDateString()}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <Link to={`/admin/requests/${req.id}`}>
                                                <Button size="sm" variant="ghost" className="h-8 group-hover:bg-white group-hover:shadow-sm px-3 rounded-lg text-indigo-600 font-black text-[10px]">
                                                    DETALLES <ChevronRight size={14} className="ml-1" />
                                                </Button>
                                            </Link>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                        {filtered.length === 0 && (
                            <div className="p-20 text-center space-y-4">
                                <div className="p-6 bg-slate-50 rounded-full inline-block border border-slate-100">
                                    <Search size={32} className="text-slate-200" />
                                </div>
                                <p className="text-slate-400 text-sm font-bold italic">No se encontraron solicitudes con esos filtros.</p>
                            </div>
                        )}
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Badge } from '../../components/ui/Badge';
import {
    Users, Wrench, ShieldAlert, UserPlus,
    ArrowRight, UserMinus, Calendar, Settings2
} from 'lucide-react';
import { supabase } from '../../lib/supabase';

export function AdminTechsPage() {
    const [techs, setTechs] = useState<any[]>([]);
    const [unassignedReqs, setUnassignedReqs] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadData();
    }, []);

    async function loadData() {
        setLoading(true);
        try {
            // Fetch all users with TECH role
            const { data: techProfiles } = await supabase
                .from('profiles')
                .select('*')
                .eq('role', 'TECH')
                .order('first_name');

            // Get active appointments for each tech
            const { data: apps } = await supabase
                .from('appointments')
                .select('id, assigned_tech_user_id, status')
                .in('status', ['CONFIRMED', 'IN_PROGRESS']);

            const techData = techProfiles?.map(tech => ({
                ...tech,
                activeJobs: apps?.filter(a => a.assigned_tech_user_id === tech.id).length || 0
            })) || [];

            setTechs(techData);

            // Fetch unassigned appointments
            const { data: unassigned } = await supabase
                .from('appointments')
                .select('*, service_requests(customer_user_id, symptoms_free_text)')
                .is('assigned_tech_user_id', null)
                .is('cancelled_at', null)
                .order('scheduled_at');

            setUnassignedReqs(unassigned || []);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    }

    async function changeRole(userId: string, currentRole: string) {
        if (!confirm(`¿Estás seguro de cambiar el rol de este usuario? (Actual: ${currentRole})`)) return;
        const newRole = currentRole === 'ADMIN' ? 'TECH' : 'ADMIN'; // Simplified toggle or select
        const { error } = await supabase.from('profiles').update({ role: newRole }).eq('id', userId);
        if (error) alert(error.message);
        loadData();
    }

    async function assignTech(appointmentId: string, techId: string) {
        const { error } = await supabase
            .from('appointments')
            .update({ assigned_tech_user_id: techId })
            .eq('id', appointmentId);

        if (error) alert(error.message);
        loadData();
    }

    async function unassignTech(appointmentId: string) {
        if (!confirm('¿Quitar técnico asignado?')) return;
        await supabase.from('appointments').update({ assigned_tech_user_id: null }).eq('id', appointmentId);
        loadData();
    }

    if (loading) return <div className="p-10 text-center animate-pulse text-indigo-600 font-bold italic">Gestionando equipo...</div>;

    return (
        <div className="space-y-8 pb-20 animate-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 flex items-center gap-2">
                        <Users className="text-blue-500" /> Gestión de Técnicos
                    </h1>
                    <p className="text-slate-500 font-medium">Asigna solicitudes y gestiona permisos del equipo técnico.</p>
                </div>
                <Button variant="outline" className="text-slate-500 hover:text-slate-800 border-slate-200">
                    <UserPlus size={18} className="mr-2" /> Agregar Técnico
                </Button>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
                {/* Technicians List */}
                <div className="xl:col-span-2 space-y-4">
                    <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 px-1">
                        Personal Técnico ({techs.length})
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {techs.map(tech => (
                            <Card key={tech.id} className="bg-white shadow-sm border-slate-200 hover:shadow-md transition-shadow group">
                                <CardContent className="p-5">
                                    <div className="flex justify-between items-start">
                                        <div className="flex gap-4">
                                            <div className="w-12 h-12 rounded-2xl bg-indigo-50 flex items-center justify-center border border-indigo-100 group-hover:bg-indigo-100 transition-colors">
                                                <Users className="text-indigo-600" />
                                            </div>
                                            <div>
                                                <h3 className="font-bold text-slate-900 leading-tight">{tech.first_name} {tech.last_name}</h3>
                                                <p className="text-xs text-slate-400 font-medium mt-0.5">{tech.email}</p>
                                                <Badge className="bg-blue-50 text-blue-600 border-blue-100 py-0 h-4 px-1.5 mt-2 font-bold text-[9px] uppercase tracking-wider">
                                                    {tech.role}
                                                </Badge>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <div className={`text-2xl font-black ${tech.activeJobs > 0 ? 'text-indigo-600' : 'text-slate-300'}`}>
                                                {tech.activeJobs}
                                            </div>
                                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Trabajos Activos</p>
                                        </div>
                                    </div>
                                    <div className="flex gap-2 mt-6 pt-4 border-t border-slate-50">
                                        <Button
                                            size="sm"
                                            variant="ghost"
                                            className="w-full text-amber-600 hover:bg-amber-50 h-8 font-bold text-xs"
                                            onClick={() => changeRole(tech.id, tech.role)}
                                        >
                                            <ShieldAlert size={14} className="mr-2" /> Promover/Rebajar
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                </div>

                {/* Assignment Desk */}
                <div className="space-y-4">
                    <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 px-1">
                        Pendientes de Asignar <ArrowRight size={18} className="text-blue-500" />
                    </h2>
                    <Card className="bg-slate-50 border-blue-200 border-dashed border-2 shadow-none rounded-2xl min-h-[400px]">
                        <CardContent className="p-4 space-y-4">
                            {unassignedReqs.length > 0 ? (
                                unassignedReqs.map(req => (
                                    <Card key={req.id} className="bg-white border-blue-100 shadow-sm rounded-xl hover:shadow-md transition-shadow">
                                        <CardContent className="p-4">
                                            <div className="flex justify-between items-start mb-3">
                                                <div className="space-y-0.5">
                                                    <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded uppercase">Urgente</span>
                                                    <h4 className="font-bold text-slate-900 line-clamp-1">{req.service_requests?.symptoms_free_text || 'Sin descripción'}</h4>
                                                </div>
                                                <div className="text-right">
                                                    <Calendar size={14} className="inline mr-1 text-slate-400" />
                                                    <span className="text-[10px] font-bold text-slate-500">
                                                        {new Date(req.scheduled_at).toLocaleDateString()}
                                                    </span>
                                                </div>
                                            </div>

                                            <div className="grid grid-cols-2 gap-2">
                                                <select
                                                    className="text-[10px] h-8 font-bold border rounded bg-slate-50 focus:bg-white"
                                                    onChange={(e) => assignTech(req.id, e.target.value)}
                                                    defaultValue=""
                                                >
                                                    <option value="" disabled>Seleccionar Técnico</option>
                                                    {techs.map(t => (
                                                        <option key={t.id} value={t.id}>{t.first_name} {t.last_name}</option>
                                                    ))}
                                                </select>
                                                <Button size="sm" className="h-8 font-bold text-[10px] bg-indigo-600 hover:bg-indigo-700">
                                                    ASIGNAR
                                                </Button>
                                            </div>
                                        </CardContent>
                                    </Card>
