                            ) : (
                                <div className="text-center py-20 text-slate-400">
                                    <Wrench className="mx-auto text-slate-200 mb-2" size={32} />
                                    <p className="text-sm font-medium italic">Todos los trabajos están asignados.</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import {
    Users, FileCheck, DollarSign,
    ArrowUpRight, Clock, Target, CheckCircle2
} from 'lucide-react';
import { supabase } from '../../lib/supabase';

export function AdminDashboardPage() {
    const [stats, setStats] = useState<any>({
        counts: {},
        conversionRate: 0,
        avgDiagTime: '0h',
        totalRevenue: 0,
        recentActivity: []
    });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadStats();
    }, []);

    async function loadStats() {
        setLoading(true);
        try {
            // 1. Fetch Status Counts
            const { data: reqs } = await supabase.from('service_requests').select('status');
            const counts = reqs?.reduce((acc: any, curr: any) => {
                acc[curr.status] = (acc[curr.status] || 0) + 1;
                return acc;
            }, {});

            // 2. Conversion: QUOTED -> APPROVED
            // Let's simplified: requests with APPROVED status / total requests that have a quote
            const { count: quotedCount } = await supabase.from('quotes').select('id', { count: 'exact', head: true });
            const { count: approvedCount } = await supabase.from('service_requests').select('id', { count: 'exact', head: true }).eq('status', 'APPROVED');
            const conversion = quotedCount ? (approvedCount || 0) / quotedCount * 100 : 0;

            // 3. Total Revenue (Approved Quotes)
            const { data: revData } = await supabase.from('quotes').select('grand_total').eq('status', 'APPROVED');
            const revenue = revData?.reduce((s, c) => s + (c.grand_total || 0), 0) || 0;

            // 4. Avg Time to Diagnosis
            // Simple approach: avg(inspections.updated_at - service_requests.created_at) where inspection=COMPLETED
            const { data: times } = await supabase
                .from('inspections')
                .select('updated_at, service_requests(created_at)')
                .eq('status', 'COMPLETED');

            let avgTimeStr = 'N/A';
            if (times && times.length > 0) {
                const totalDiff = times.reduce((s, t: any) => {
                    const diff = new Date(t.updated_at).getTime() - new Date(t.service_requests.created_at).getTime();
                    return s + diff;
                }, 0);
                const avgHours = totalDiff / times.length / (1000 * 60 * 60);
                avgTimeStr = `${avgHours.toFixed(1)}h`;
            }

            // 5. Recent Activity
            const { data: activity } = await supabase
                .from('audit_logs')
                .select('*')
                .order('created_at', { ascending: false })
                .limit(5);

            setStats({
                counts: counts || {},
                conversionRate: conversion.toFixed(1),
                avgDiagTime: avgTimeStr,
                totalRevenue: revenue,
                recentActivity: activity || []
            });
        } catch (err) {
            console.error('Error loading stats:', err);
        } finally {
            setLoading(false);
        }
    }

    if (loading) return <div className="p-10 text-center animate-pulse">Analizando métricas...</div>;

    return (
        <div className="space-y-6 animate-in">
            <div className="flex justify-between items-end">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Panel Administrativo</h1>
                    <p className="text-muted-foreground">Monitoreo en tiempo real de operaciones y rendimiento.</p>
                </div>
                <button onClick={loadStats} className="text-sm font-medium text-primary hover:underline">Sincronizar datos</button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                <Card className="border-t-4 border-t-primary shadow-sm hover:shadow-md transition-shadow">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-xs font-bold text-muted-foreground uppercase flex justify-between">
                            Conversión <Target size={14} className="text-primary" />
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-bold">{stats.conversionRate}%</div>
                        <p className="text-[10px] text-muted-foreground mt-1 font-medium">QUOTED → APPROVED</p>
                    </CardContent>
                </Card>

                <Card className="border-t-4 border-t-amber-500 shadow-sm hover:shadow-md transition-shadow">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-xs font-bold text-muted-foreground uppercase flex justify-between">
                            Tiempo Diag. <Clock size={14} className="text-amber-500" />
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-bold">{stats.avgDiagTime}</div>
                        <p className="text-[10px] text-muted-foreground mt-1 font-medium">Promedio hasta diagnóstico</p>
                    </CardContent>
                </Card>

                <Card className="border-t-4 border-t-success shadow-sm hover:shadow-md transition-shadow">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-xs font-bold text-muted-foreground uppercase flex justify-between">
                            Ventas Netas <DollarSign size={14} className="text-success" />
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-bold text-success">${stats.totalRevenue.toLocaleString()}</div>
                        <p className="text-[10px] text-success mt-1 font-bold flex items-center gap-1">
                            <ArrowUpRight size={10} /> Presupuestos Aprobados
                        </p>
                    </CardContent>
                </Card>

                <Card className="border-t-4 border-t-info shadow-sm hover:shadow-md transition-shadow">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-xs font-bold text-muted-foreground uppercase flex justify-between">
                            Pendientes <FileCheck size={14} className="text-info" />
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-bold text-info">{stats.counts['SCHEDULED'] || 0}</div>
                        <p className="text-[10px] text-muted-foreground mt-1 font-medium italic">Esperando ejecución</p>
                    </CardContent>
                </Card>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Status Breakdown */}
                <Card className="lg:col-span-1">
                    <CardHeader>
                        <CardTitle className="text-sm font-bold flex items-center gap-2">
                            <CheckCircle2 size={16} className="text-primary" /> Distribución de Estados
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-3">
                        {Object.entries(stats.counts).map(([status, count]: [string, any]) => (
                            <div key={status} className="flex justify-between items-center text-sm p-2 bg-slate-50 rounded-lg">
                                <span className="font-medium text-slate-600">{status.replace('_', ' ')}</span>
                                <span className="bg-white px-2 py-0.5 rounded border border-slate-200 font-bold">{count}</span>
                            </div>
                        ))}
                    </CardContent>
                </Card>

                {/* Recent Activity */}
                <Card className="lg:col-span-2">
                    <CardHeader>
                        <CardTitle className="text-sm font-bold flex items-center gap-2">
                            <Users size={16} className="text-primary" /> Actividad del Sistema (Audit Log)
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        {stats.recentActivity.length > 0 ? (
                            stats.recentActivity.map((log: any) => (
                                <div key={log.id} className="flex justify-between items-center border-b border-slate-100 last:border-0 pb-3">
                                    <div className="space-y-0.5">
                                        <p className="text-sm font-bold text-slate-800 uppercase tracking-tight">{log.action.replace('_', ' ')}</p>
                                        <p className="text-[10px] text-slate-400">ID Entidad: {log.entity_id?.split('-')[0]}</p>
                                    </div>
                                    <span className="text-[10px] font-medium text-slate-500 bg-slate-100 px-2 py-0.5 rounded">
                                        {new Date(log.created_at).toLocaleString()}
                                    </span>
                                </div>
                            ))
                        ) : (
                            <div className="text-center py-10 text-muted-foreground text-sm italic">
                                No hay actividad reciente registrada.
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '../../components/ui/Card';
import { useToast } from '../../components/ui/Toast';
import { supabase } from '../../lib/supabase';
import { User, Wrench, ArrowLeft } from 'lucide-react';

export function LoginPage() {
    const { toast } = useToast();
    const location = useLocation();
    const [loading, setLoading] = useState(false);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [role, setRole] = useState<'CUSTOMER' | 'TECH' | 'ADMIN' | null>(null);

    useEffect(() => {
        const params = new URLSearchParams(location.search);
        const r = params.get('role');
        if (r === 'TECH' || r === 'CUSTOMER' || r === 'ADMIN') {
            setRole(r as any);
        }
    }, [location]);

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        try {
            const { error } = await supabase.auth.signInWithPassword({
                email,
                password,
            });

            if (error) throw error;

            toast({ title: 'Éxito', description: 'Inicio de sesión exitoso', type: 'success' });
        } catch (error: any) {
            console.error('Error in login:', error);
            toast({ title: 'Error', description: error.message || 'Credenciales inválidas', type: 'error' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="flex items-center justify-center min-h-[80vh] px-4">
            <Card className="w-full max-w-md animate-in shadow-2xl rounded-[2rem] overflow-hidden border-slate-100">
                <div className={`h-2 w-full ${role === 'TECH' ? 'bg-slate-800' : role === 'ADMIN' ? 'bg-indigo-600' : 'bg-primary'}`}></div>
                <CardHeader className="text-center pt-10">
                    <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 ${role === 'TECH' ? 'bg-slate-100 text-slate-600' : role === 'ADMIN' ? 'bg-indigo-50 text-indigo-600' : 'bg-primary/10 text-primary'}`}>
                        {role === 'TECH' ? <Wrench size={32} /> : <User size={32} />}
                    </div>
                    <CardTitle className="text-3xl font-black text-slate-900">
                        {role === 'TECH' ? 'Acceso Técnico' : role === 'ADMIN' ? 'Panel Control' : 'Bienvenido'}
                    </CardTitle>
                    <CardDescription className="text-slate-500 font-bold uppercase tracking-tight text-[10px]">
                        {role === 'TECH' ? 'Gestiona tus órdenes de trabajo' : role === 'ADMIN' ? 'Administración del Sistema' : 'Inicia sesión para ver tus servicios'}
                    </CardDescription>
                </CardHeader>
                <CardContent className="px-8 pb-8">
                    <form className="space-y-4" onSubmit={handleLogin}>
                        <Input
                            label="Correo electrónico"
                            type="email"
                            placeholder="tu@correo.com"
                            required
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="h-12 rounded-xl"
                        />
                        <div className="space-y-1">
                            <Input
                                label="Contraseña"
                                type="password"
                                required
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                className="h-12 rounded-xl"
                            />
                            <div className="text-right">
                                <button type="button" className="text-[10px] text-primary font-bold hover:underline">¿Olvidaste tu contraseña?</button>
                            </div>
                        </div>
                        <Button
                            type="submit"
                            fullWidth
                            loading={loading}
                            className={`h-14 rounded-2xl font-black mt-2 shadow-xl ${role === 'TECH' ? 'bg-slate-800 hover:bg-slate-900' : role === 'ADMIN' ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-primary shadow-primary/20'}`}
                        >
                            INGRESAR
                        </Button>
                    </form>
                </CardContent>
                <CardFooter className="flex flex-col items-center pb-10 gap-3 border-t border-slate-50 pt-6">
                    <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">
                        ¿No tienes cuenta? <Link to={`/auth/register${role ? `?role=${role}` : ''}`} className="text-primary hover:underline ml-1">Regístrate</Link>
                    </p>
                    <Link to="/" className="text-[9px] text-slate-300 hover:text-slate-500 font-bold uppercase tracking-tighter flex items-center gap-1">
                        <ArrowLeft size={10} /> Volver al inicio
                    </Link>
                </CardFooter>
            </Card>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '../../components/ui/Card';
import { useToast } from '../../components/ui/Toast';
import { supabase } from '../../lib/supabase';
import { Mail, ArrowLeft, User, Wrench } from 'lucide-react';

export function RegisterPage() {
    const { toast } = useToast();
    const location = useLocation();
    const [loading, setLoading] = useState(false);
    const [registered, setRegistered] = useState(false);

    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [firstName, setFirstName] = useState('');
    const [lastName, setLastName] = useState('');
    const [role, setRole] = useState<'CUSTOMER' | 'TECH'>('CUSTOMER');

    useEffect(() => {
        const params = new URLSearchParams(location.search);
        const r = params.get('role');
        if (r === 'TECH' || r === 'CUSTOMER') {
            setRole(r);
        }
    }, [location]);

    const handleRegister = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        try {
            const { data, error } = await supabase.auth.signUp({
                email,
                password,
                options: {
                    data: {
                        role: role,
                        first_name: firstName,
                        last_name: lastName
                    }
                }
            });

            if (error) throw error;

            if (data.user && !data.session) {
                setRegistered(true);
                toast({ title: 'Revisa tu correo', description: 'Te hemos enviado un enlace para confirmar tu cuenta', type: 'info' });
            } else {
                toast({ title: 'Cuenta Creada', description: '¡Bienvenido a Denver Auto Care!', type: 'success' });
            }
        } catch (error: any) {
            console.error('Error in register:', error);
            toast({ title: 'Error', description: error.message || 'Error al crear la cuenta', type: 'error' });
        } finally {
            setLoading(false);
        }
    };

    if (registered) {
        return (
            <div className="flex items-center justify-center min-h-[75vh] px-4">
                <Card className="w-full max-w-md animate-in text-center p-8 rounded-3xl shadow-2xl">
                    <div className="w-20 h-20 bg-primary/10 text-primary rounded-full flex items-center justify-center mx-auto mb-6">
                        <Mail size={40} />
                    </div>
                    <CardHeader>
                        <CardTitle className="text-2xl font-black">¡Casi listo!</CardTitle>
                        <CardDescription className="text-slate-500 font-medium">
                            Hemos enviado un enlace de confirmación a <br />
                            <strong className="text-slate-900">{email}</strong>.
                        </CardDescription>
                    </CardHeader>
                    <CardFooter className="flex flex-col gap-4 mt-4">
                        <Link to="/auth/login" className="w-full">
                            <Button fullWidth className="h-12 rounded-xl">IR AL INICIO DE SESIÓN</Button>
                        </Link>
                        <button
                            onClick={() => setRegistered(false)}
                            className="text-xs text-slate-400 hover:text-primary font-bold uppercase tracking-widest flex items-center justify-center gap-1"
                        >
                            <ArrowLeft size={12} /> CAMBIAR CORREO
                        </button>
                    </CardFooter>
                </Card>
            </div>
        );
    }

    return (
        <div className="flex items-center justify-center min-h-[85vh] px-4 py-12">
            <Card className="w-full max-w-lg animate-in shadow-2xl border-slate-100 rounded-[2.5rem] overflow-hidden">
                <div className={`h-2 w-full ${role === 'TECH' ? 'bg-slate-800' : 'bg-primary'}`}></div>
                <CardHeader className="text-center pt-10">
                    <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 ${role === 'TECH' ? 'bg-slate-100 text-slate-600' : 'bg-primary/10 text-primary'}`}>
                        {role === 'TECH' ? <Wrench size={32} /> : <User size={32} />}
                    </div>
                    <CardTitle className="text-3xl font-black text-slate-900">
                        {role === 'TECH' ? 'Únete al Equipo' : 'Regístrate'}
                    </CardTitle>
                    <CardDescription className="text-slate-500 font-bold uppercase tracking-tight text-[10px]">
                        {role === 'TECH' ? 'Perfil Profesional de Técnico' : 'Perfil de Cliente Denver Auto Care'}
                    </CardDescription>
                </CardHeader>
                <CardContent className="px-10 pb-10">
                    <form className="space-y-4" onSubmit={handleRegister}>
                        <div className="grid grid-cols-2 gap-4">
                            <Input
                                label="Nombre"
                                placeholder="Tu nombre"
                                required
                                value={firstName}
                                onChange={(e) => setFirstName(e.target.value)}
                                className="h-12 rounded-xl"
                            />
                            <Input
                                label="Apellido"
                                placeholder="Tu apellido"
                                required
                                value={lastName}
                                onChange={(e) => setLastName(e.target.value)}
                                className="h-12 rounded-xl"
                            />
                        </div>
                        <Input
                            label="Correo electrónico"
                            type="email"
                            placeholder="tu@correo.com"
                            required
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="h-12 rounded-xl"
                        />
                        <Input
                            label="Contraseña"
                            type="password"
                            required
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            hint="Mínimo 6 caracteres"
                            className="h-12 rounded-xl"
                        />
                        <Button
                            type="submit"
                            fullWidth
                            loading={loading}
                            className={`h-14 rounded-2xl font-black mt-4 shadow-xl ${role === 'TECH' ? 'bg-slate-800 hover:bg-slate-900' : 'bg-primary shadow-primary/20'}`}
                        >
                            {role === 'TECH' ? 'CREAR CUENTA TÉCNICA' : 'CREAR MI CUENTA'}
                        </Button>
                    </form>
                </CardContent>
                <CardFooter className="flex flex-col items-center pb-10 gap-2 border-t border-slate-50 pt-6">
                    <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">
                        ¿Ya tienes cuenta? <Link to="/auth/login" className="text-primary hover:underline ml-1">Ingresa aquí</Link>
                    </p>
                    <Link to="/" className="text-[9px] text-slate-300 hover:text-slate-500 font-bold uppercase tracking-tighter flex items-center gap-1">
                        <ArrowLeft size={10} /> Volver al inicio
                    </Link>
                </CardFooter>
            </Card>
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Bot, User, AlertTriangle, CheckCircle, ChevronRight, Send, Loader2 } from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';
import { supabase } from '../../lib/supabase';
import { useToast } from '../../components/ui/Toast';

interface Message {
    id: string;
    role: 'bot' | 'user';
    text: string;
    options?: { label: string; value: any; action?: string }[];
    component?: React.ReactNode;
}

interface SymptomTag {
    id: string;
    code: string;
    label: string;
    category: string;
    severity_hint: 'LOW' | 'MED' | 'HIGH';
}

interface Vehicle {
    id: string;
    make: string;
    model: string;
    year: number;
}

export function ChatbotPage() {
    const { user } = useAuth();
    const { toast } = useToast();
    const navigate = useNavigate();
    const [messages, setMessages] = useState<Message[]>([]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const [sessionId, setSessionId] = useState<string | null>(null);
    const scrollRef = useRef<HTMLDivElement>(null);

    // Flow State
    const [step, setStep] = useState<'WELCOME' | 'VEHICLE' | 'SYMPTOMS' | 'TRIAGE' | 'SUMMARY' | 'FINISHED'>('WELCOME');
    const [vehicles, setVehicles] = useState<Vehicle[]>([]);
    const [symptomTags, setSymptomTags] = useState<SymptomTag[]>([]);
    const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
    const [selectedSymptoms, setSelectedSymptoms] = useState<string[]>([]);
    const [freeTextSymptom, setFreeTextSymptom] = useState('');
    const [triageRisk, setTriageRisk] = useState<'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL'>('LOW');

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    useEffect(() => {
        const initChat = async () => {
            if (!user) return;

            // 1. Create session
            const { data: session, error: sErr } = await supabase
                .from('chatbot_sessions')
                .insert({ customer_user_id: user.id })
                .select()
                .single();

            if (sErr) return console.error(sErr);
            setSessionId(session.id);

            // 2. Load Vehicles
            const { data: vData } = await supabase.from('vehicles').select('id, make, model, year').eq('owner_user_id', user.id);
            setVehicles(vData || []);

            // 3. Load Symptoms
            const { data: syData } = await supabase.from('symptom_tags').select('*');
            setSymptomTags(syData || []);

            // 4. Welcome Message
            addBotMessage("¡Hola! Soy tu asistente de Denver Mobile Auto Care. Te ayudaré a diagnosticar tu problema y agendar tu servicio.");
            setTimeout(() => askVehicle(vData || []), 1000);
        };

        initChat();
    }, [user]);

    const addBotMessage = (text: string, options?: Message['options'], component?: React.ReactNode) => {
        const id = Math.random().toString(36).substr(2, 9);
        setMessages((prev: Message[]) => [...prev, { id, role: 'bot', text, options, component }]);
        if (sessionId) {
            supabase.from('chatbot_messages').insert({ session_id: sessionId, sender: 'BOT', content: text }).then();
        }
    };

    const addUserMessage = (text: string) => {
        const id = Math.random().toString(36).substr(2, 9);
        setMessages((prev: Message[]) => [...prev, { id, role: 'user', text }]);
        if (sessionId) {
            supabase.from('chatbot_messages').insert({ session_id: sessionId, sender: 'USER', content: text }).then();
        }
    };

    const askVehicle = (userVehicles: Vehicle[]) => {
        setStep('VEHICLE');
        if (userVehicles.length > 0) {
            const options = userVehicles.map(v => ({
                label: `${v.make} ${v.model} (${v.year})`,
                value: v.id,
                action: 'select_vehicle'
            }));
            options.push({ label: "+ Agregar otro vehículo", value: 'new', action: 'add_vehicle' });
            addBotMessage("Primero, ¿en cuál de tus vehículos hay un problema?", options);
        } else {
            addBotMessage("Veo que no tienes vehículos registrados. Por favor, agrega uno en la sección de 'Vehículos' o dime la marca y modelo aquí.");
            // For simplicity in this guided flow, we'll ask them to go to vehicles if none
            setMessages((prev: Message[]) => [...prev, {
                id: 'btn-vehicles',
                role: 'bot',
                text: "Necesitas registrar un vehículo para continuar.",
                options: [{ label: "Ir a Mis Vehículos", value: '/app/vehicles', action: 'navigate' }]
            }]);
        }
    };

    const handleOptionClick = async (option: { label: string; value: any; action?: string }) => {
        addUserMessage(option.label);

        if (option.action === 'select_vehicle') {
            const v = vehicles.find(veh => veh.id === option.value);
            setSelectedVehicle(v || null);
            if (sessionId) {
                await supabase.from('chatbot_sessions').update({ vehicle_id: option.value }).eq('id', sessionId);
            }
            addBotMessage(`Perfecto, revisemos el ${v?.make}. ¿Qué síntomas presenta? Selecciona los que apliquen:`);
            setStep('SYMPTOMS');
            renderSymptomSelector();
        } else if (option.action === 'navigate') {
            navigate(option.value);
        } else if (option.action === 'finish_symptoms') {
            processSymptoms();
        } else if (option.action === 'triage_answer') {
            handleTriageResponse(option.value);
        } else if (option.action === 'create_request') {
            createServiceRequest();
        }
    };

    const renderSymptomSelector = () => {
        setMessages((prev: Message[]) => [...prev, {
            id: 'symptom-picker',
            role: 'bot',
            text: "Puedes seleccionar varios de la lista o escribir uno nuevo abajo.",
            component: (
                <div className="grid grid-cols-2 gap-2 mt-2">
                    {symptomTags.map(s => (
                        <Button
                            key={s.id}
                            variant="outline"
                            size="sm"
                            className="text-xs justify-start h-auto py-2 px-3 whitespace-normal text-left"
                            onClick={() => toggleSymptom(s.id)}
                        >
                            {selectedSymptoms.includes(s.id) ? <CheckCircle size={12} className="mr-1 text-primary" /> : null}
                            {s.label}
                        </Button>
                    ))}
                    <Button
                        fullWidth
                        className="col-span-2 mt-2"
                        onClick={() => handleOptionClick({ label: "Listo, continuar", value: true, action: 'finish_symptoms' })}
                    >
                        Continuar <ChevronRight size={14} />
                    </Button>
                </div>
            )
        }]);
    };

    const toggleSymptom = (id: string) => {
        setSelectedSymptoms((prev: string[]) => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    };

    const processSymptoms = () => {
        setStep('TRIAGE');
        addBotMessage("Entendido. Ahora unas preguntas rápidas de seguridad:");
        setTimeout(() => {
            addBotMessage("¿Hay alguna luz roja encendida en el tablero, escuchas ruidos metálicos fuertes o sientes que los frenos no responden bien?", [
                { label: "Sí, algo de eso sucede", value: 'HIGH', action: 'triage_answer' },
                { label: "No, el carro se siente seguro pero falla", value: 'LOW', action: 'triage_answer' }
            ]);
        }, 800);
    };

    const handleTriageResponse = (risk: string) => {
        setTriageRisk(risk as any);
        if (risk === 'HIGH') {
            addBotMessage("⚠️ RECOMENDACIÓN CRÍTICA: Basado en tus síntomas, te sugerimos NO conducir el vehículo. Podría ser peligroso o causar daños mayores. ¿Deseas que preparemos un diagnóstico general a domicilio?", [
                { label: "Sí, preparar solicitud", value: true, action: 'create_request' }
            ]);
        } else {
            addBotMessage("Gracias. He analizado tus datos y parece que necesitas una revisión técnica avanzada. ¿Procedemos a crear la solicitud de servicio?", [
                { label: "Sí, crear solicitud", value: true, action: 'create_request' }
            ]);
        }
        setStep('SUMMARY');
    };

    const createServiceRequest = async () => {
        if (!user || !selectedVehicle) return;
        setLoading(true);

        try {
            // Determine probable service
            let serviceCode = 'DIAG_GENERAL';
            const categories = symptomTags.filter(s => selectedSymptoms.includes(s.id)).map(s => s.category);
            if (categories.includes('Frenos')) serviceCode = 'BRAKES';
            else if (categories.includes('Suspensión')) serviceCode = 'SUSPENSION';
            else if (categories.includes('Fluidos')) serviceCode = 'FLUIDS';

            const { data: service } = await supabase.from('service_catalog').select('id').eq('code', serviceCode).single();

            // 1. Create Request
            const { data: req, error: rErr } = await supabase
                .from('service_requests')
                .insert({
                    customer_user_id: user.id,
                    vehicle_id: selectedVehicle.id,
                    requested_service_id: service?.id,
                    status: 'DRAFT',
                    triage_risk: triageRisk,
                    triage_notes: `Síntomas: ${selectedSymptoms.length} seleccionados. Triage: ${triageRisk}.`,
                    symptoms_free_text: freeTextSymptom
                })
                .select()
                .single();

            if (rErr) throw rErr;

            // 2. Insert Junction Symptoms
            if (selectedSymptoms.length > 0) {
                await supabase.from('request_symptoms').insert(
                    selectedSymptoms.map(sid => ({ request_id: req.id, symptom_id: sid }))
                );
            }

            addBotMessage("¡Listo! He creado un borrador de tu solicitud. Ahora solo falta agendar la visita de nuestro técnico.");
            setStep('FINISHED');
            setMessages((prev: Message[]) => [...prev, {
                id: 'final-cta',
                role: 'bot',
                text: "Haz clic abajo para elegir fecha y hora:",
                options: [{ label: "Agendar Visita Ahora", value: `/app/schedule?request_id=${req.id}`, action: 'navigate' }]
            }]);

        } catch (error: any) {
            toast({ title: 'Error', description: error.message, type: 'error' });
        } finally {
            setLoading(false);
        }
    };

    const handleSendInput = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        addUserMessage(input);
        const val = input;
        setInput('');

        if (step === 'SYMPTOMS') {
            setFreeTextSymptom(val);
            addBotMessage("He guardado tu descripción. ¿Podemos continuar con las preguntas de seguridad?");
            setMessages((prev: Message[]) => [...prev, {
                id: 'cont-symptom',
                role: 'bot',
                text: "¿Terminamos con los síntomas?",
                options: [{ label: "Sí, continuar", value: true, action: 'finish_symptoms' }]
            }]);
        } else {
            addBotMessage("Entendido. Por favor selecciona una de las opciones guiadas para continuar mejor.");
        }
    };

    return (
        <div className="max-w-2xl mx-auto h-[calc(100vh-12rem)] min-h-[500px] flex flex-col pt-4 animate-in">
            <div className="mb-4 flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold">Diagnóstico Inteligente</h1>
                    <p className="text-muted-foreground">Cuéntame qué le pasa a tu auto.</p>
                </div>
                {triageRisk === 'HIGH' && (
                    <div className="flex items-center gap-2 px-3 py-1 bg-destructive/10 text-destructive rounded-full text-xs font-bold border border-destructive/20 animate-pulse">
                        <AlertTriangle size={14} /> ALTO RIESGO
                    </div>
                )}
            </div>

            <Card className="flex-1 flex flex-col overflow-hidden border-slate-200 shadow-xl rounded-2xl">
                <CardHeader className="border-b border-border bg-slate-50/50 pb-4">
                    <CardTitle className="flex items-center gap-2 text-slate-700">
                        <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center text-white">
                            <Bot size={18} />
                        </div>
                        Chatbot Denver
                    </CardTitle>
                </CardHeader>

                <CardContent
                    ref={scrollRef}
                    className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth bg-[#f8fafc]"
                >
                    {messages.map((m: Message) => (
                        <div key={m.id} className={`flex gap-3 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
                            <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 shadow-sm ${m.role === 'bot' ? 'bg-white border border-slate-200 text-primary' : 'bg-primary text-white'
                                }`}>
                                {m.role === 'bot' ? <Bot size={16} /> : <User size={16} />}
                            </div>
                            <div className="max-w-[85%] space-y-2">
                                <div className={`p-4 shadow-sm ${m.role === 'user'
                                    ? 'bg-primary text-white rounded-2xl rounded-tr-none'
                                    : 'bg-white border border-slate-100 text-slate-700 rounded-2xl rounded-tl-none'
                                    }`}>
                                    <p className="text-sm leading-relaxed">{m.text}</p>
                                    {m.component}
                                </div>

                                {m.options && (
                                    <div className={`flex flex-wrap gap-2 ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                        {m.options.map((opt: { label: string; value: any; action?: string }, i) => (
                                            <Button
                                                key={i}
                                                variant="outline"
                                                size="sm"
                                                className="bg-white hover:bg-primary hover:text-white border-primary/20 text-primary rounded-full transition-all duration-200"
                                                onClick={() => handleOptionClick(opt)}
                                            >
                                                {opt.label}
                                            </Button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                    {loading && (
                        <div className="flex gap-3">
                            <div className="w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center text-primary">
                                <Loader2 size={16} className="animate-spin" />
                            </div>
                            <div className="p-3 bg-white border border-slate-100 rounded-2xl rounded-tl-none">
                                <div className="flex gap-1">
                                    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce" />
                                    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.2s]" />
                                    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.4s]" />
                                </div>
                            </div>
                        </div>
                    )}
                </CardContent>

                <CardFooter className="p-4 bg-white border-t border-slate-100">
                    <form className="flex w-full gap-2" onSubmit={handleSendInput}>
                        <div className="flex-1">
                            <Input
                                value={input}
                                onChange={(e) => setInput(e.target.value)}
                                placeholder={step === 'SYMPTOMS' ? "Escribe detalles adicionales..." : "Escribe tu respuesta..."}
                                className="bg-slate-50 border-none focus-visible:ring-primary shadow-inner"
                            />
                        </div>
                        <Button type="submit" size="icon" disabled={!input.trim() || loading} className="rounded-xl shadow-lg shadow-primary/20">
                            <Send size={18} />
                        </Button>
                    </form>
                </CardFooter>
            </Card>
        </div>
    );
}

