import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Badge } from '../../components/ui/Badge';
import { Wrench, Calendar, FileText, CheckCircle, PlusCircle, Car, ChevronRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';

export function CustomerDashboardPage() {
    const { user, profile } = useAuth();
    const [requests, setRequests] = useState<any[]>([]);
    const [vehicles, setVehicles] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (user) loadData();
    }, [user]);

    async function loadData() {
        setLoading(true);
        const [reqRes, vehRes] = await Promise.all([
            supabase
                .from('service_requests')
                .select('*, vehicles(make, model, year), service_catalog(name)')
                .eq('customer_id', user!.id)
                .order('created_at', { ascending: false })
                .limit(5),
            supabase
                .from('vehicles')
                .select('*')
                .eq('customer_id', user!.id)
                .order('created_at', { ascending: false })
        ]);

        setRequests(reqRes.data || []);
        setVehicles(vehRes.data || []);
        setLoading(false);
    }

    const active = requests.filter(r => !['COMPLETED', 'CANCELED', 'DECLINED'].includes(r.status));
    const completed = requests.filter(r => r.status === 'COMPLETED');
    const pending = requests.filter(r => r.status === 'QUOTED');

    const STATUS_LABEL: Record<string, string> = {
        SUBMITTED: 'Solicitado', SCHEDULED: 'Programado', DIAGNOSED: 'Diagnosticado',
        QUOTED: 'Pendiente Precio', APPROVED: 'Aprobado', COMPLETED: 'Completado',
        CANCELED: 'Cancelado', DECLINED: 'Rechazado',
    };
    const STATUS_BADGE: Record<string, any> = {
        SUBMITTED: 'warning', SCHEDULED: 'secondary', DIAGNOSED: 'secondary',
        QUOTED: 'warning', APPROVED: 'success', COMPLETED: 'success',
        CANCELED: 'destructive', DECLINED: 'destructive',
    };

    return (
        <div className="space-y-6 animate-in">
            {/* Header */}
            <div className="flex justify-between items-center flex-wrap gap-4">
                <div>
                    <h1 className="text-2xl font-bold">
                        Hola, {profile?.first_name || 'Cliente'} 👋
                    </h1>
                    <p className="text-muted-foreground">Aquí está el resumen de tus vehículos y servicios.</p>
                </div>
                <Link to="/app/schedule">
                    <Button className="gap-2">
                        <Calendar size={16} /> Agendar Cita
                    </Button>
                </Link>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card className="bg-primary/5 border-primary/20">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2 text-primary">
                            <Wrench size={18} /> Servicios Activos
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-bold">{loading ? '—' : active.length}</div>
                        <p className="text-sm text-muted-foreground mt-1">En proceso o programados</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <CheckCircle size={18} className="text-success" /> Completados
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-bold">{loading ? '—' : completed.length}</div>
                        <p className="text-sm text-muted-foreground mt-1">Servicios finalizados</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <FileText size={18} className="text-muted-foreground" /> Espera Aprobación
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-3xl font-bold">{loading ? '—' : pending.length}</div>
                        <p className="text-sm text-muted-foreground mt-1">
                            {pending.length > 0 ? (
                                <Link to="/app/requests" className="text-warning font-semibold hover:underline">
                                    Ver presupuestos →
                                </Link>
                            ) : 'Sin cotizaciones pendientes'}
                        </p>
                    </CardContent>
                </Card>
            </div>

            {/* Vehicles + Recent Requests */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Vehicles */}
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between">
                        <CardTitle className="flex items-center gap-2"><Car size={18} /> Mis Vehículos</CardTitle>
                        <Link to="/app/vehicles">
                            <Button variant="ghost" size="sm" className="text-xs">Administrar</Button>
                        </Link>
                    </CardHeader>
                    <CardContent className="space-y-2">
                        {loading ? (
                            <div className="space-y-2">
                                {[1, 2].map(i => <div key={i} className="h-14 bg-slate-100 rounded-lg animate-pulse" />)}
                            </div>
                        ) : vehicles.length === 0 ? (
                            <div className="text-center py-10 text-muted-foreground">
                                <Car size={32} className="mx-auto mb-2 opacity-20" />
                                <p className="text-sm">No tienes vehículos registrados</p>
                                <Link to="/app/vehicles">
                                    <Button variant="outline" size="sm" className="mt-3 gap-2">
                                        <PlusCircle size={14} /> Agregar Vehículo
                                    </Button>
                                </Link>
                            </div>
                        ) : (
                            vehicles.map(v => (
                                <div key={v.id} className="flex items-center justify-between p-3 border border-border rounded-lg hover:bg-slate-50 transition-colors">
                                    <div>
                                        <h4 className="font-semibold text-sm">{v.year} {v.make} {v.model}</h4>
                                        <p className="text-xs text-muted-foreground">
                                            {v.license_plate && `Placa: ${v.license_plate}`}
                                            {v.mileage && ` • ${v.mileage.toLocaleString()} mi`}
                                        </p>
                                    </div>
                                    <Link to="/app/vehicles">
                                        <Button variant="ghost" size="sm"><ChevronRight size={16} /></Button>
                                    </Link>
                                </div>
                            ))
                        )}
                    </CardContent>
                </Card>

                {/* Recent Requests */}
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between">
                        <CardTitle>Servicios Recientes</CardTitle>
                        <Link to="/app/requests">
                            <Button variant="ghost" size="sm" className="text-xs">Ver todos</Button>
                        </Link>
                    </CardHeader>
                    <CardContent className="space-y-2">
                        {loading ? (
                            <div className="space-y-2">
                                {[1, 2, 3].map(i => <div key={i} className="h-14 bg-slate-100 rounded-lg animate-pulse" />)}
                            </div>
                        ) : requests.length === 0 ? (
                            <div className="text-center py-10 text-muted-foreground">
                                <Wrench size={32} className="mx-auto mb-2 opacity-20" />
                                <p className="text-sm">Aún no tienes solicitudes</p>
                                <Link to="/app/schedule">
                                    <Button variant="outline" size="sm" className="mt-3 gap-2">
                                        <Calendar size={14} /> Agendar primer servicio
                                    </Button>
                                </Link>
                            </div>
                        ) : (
                            requests.slice(0, 4).map(req => (
                                <Link key={req.id} to={`/app/requests/${req.id}`}>
                                    <div className="flex items-center justify-between p-3 border border-border rounded-lg hover:bg-slate-50 transition-colors cursor-pointer">
                                        <div>
                                            <p className="text-sm font-medium">
                                                {req.service_catalog?.name || req.description || 'Servicio General'}
                                            </p>
                                            <p className="text-xs text-muted-foreground">
                                                {req.vehicles ? `${req.vehicles.year} ${req.vehicles.make} ${req.vehicles.model}` : '—'}
                                                {' · '}{new Date(req.created_at).toLocaleDateString('es-US', { day: '2-digit', month: 'short' })}
                                            </p>
                                        </div>
                                        <Badge variant={STATUS_BADGE[req.status] || 'outline'} className="text-[10px]">
                                            {STATUS_LABEL[req.status] || req.status}
                                        </Badge>
                                    </div>
                                </Link>
                            ))
                        )}
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Select } from '../../components/ui/Select';
import { useToast } from '../../components/ui/Toast';

export function OnboardingPage() {
    const { session, profile, refreshProfile } = useAuth();
    const navigate = useNavigate();
    const { toast } = useToast();
    const [loading, setLoading] = useState(false);

    // If the user already has a complete profile, skip onboarding
    useEffect(() => {
        if (profile && profile.first_name && profile.last_name) {
            if (profile.role === 'CUSTOMER') navigate('/app', { replace: true });
            else if (profile.role === 'TECH') navigate('/tech', { replace: true });
            else if (profile.role === 'ADMIN') navigate('/admin', { replace: true });
        }
    }, [profile, navigate]);

    const [form, setForm] = useState({
        firstName: '',
        lastName: '',
        phone: '',
        channel: 'EMAIL'
    });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        if (!session?.user) return;

        // Basic E.164 phone validation (e.g. +1234567890)
        const phoneRegex = /^\+[1-9]\d{1,14}$/;
        if (form.phone && !phoneRegex.test(form.phone)) {
            toast({ title: 'Error de Validación', description: 'Formato de teléfono inválido. Use formato internacional (ej. +17205551234)', type: 'error' });
            setLoading(false);
            return;
        }

        try {
            const { error } = await supabase.from('profiles').upsert({
                user_id: session.user.id,
                role: 'CUSTOMER',
                first_name: form.firstName,
                last_name: form.lastName,
                phone: form.phone || null,
                preferred_channel: form.channel as any
            });

            if (error) throw error;

            toast({ title: '¡Éxito!', description: 'Perfil configurado correctamente', type: 'success' });
            await refreshProfile(); // Context updates, triggering RoleGuard
            navigate('/app', { replace: true });
        } catch (error: any) {
            console.error('Error in onboarding:', error);
            toast({ title: 'Error', description: error.message || 'Error al guardar el perfil', type: 'error' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-[80vh] flex flex-col items-center justify-center p-4">
            <div className="w-full max-w-md bg-white rounded-xl shadow-lg p-8 border border-slate-100">
                <div className="text-center mb-8">
                    <h1 className="text-2xl font-bold text-slate-800">Completa tu perfil</h1>
                    <p className="text-slate-500 mt-2 text-sm">
                        Necesitamos algunos datos para brindarte un mejor servicio
                    </p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                        <Input
                            label="Nombre(s)"
                            required
                            value={form.firstName}
                            onChange={(e) => setForm({ ...form, firstName: e.target.value })}
                            placeholder="Ej. Juan"
                        />
                        <Input
                            label="Apellidos"
                            required
                            value={form.lastName}
                            onChange={(e) => setForm({ ...form, lastName: e.target.value })}
                            placeholder="Ej. Pérez"
                        />
                    </div>

                    <Input
                        label="Teléfono Móvil (Opcional)"
                        type="tel"
                        value={form.phone}
                        onChange={(e) => setForm({ ...form, phone: e.target.value })}
                        placeholder="+1 720 555 1234"
                        hint="Formato internacional, ej: +17205551234"
                    />

                    <Select
                        label="Canal de Contacto Preferido"
                        value={form.channel}
                        onChange={(e) => setForm({ ...form, channel: e.target.value })}
                        options={[
                            { value: 'EMAIL', label: 'Correo Electrónico' },
                            { value: 'SMS', label: 'Mensaje de Texto (SMS)' },
                            { value: 'WHATSAPP', label: 'WhatsApp' },
                            { value: 'TELEGRAM', label: 'Telegram' }
                        ]}
                    />

                    <div className="pt-4">
                        <Button type="submit" variant="primary" fullWidth loading={loading}>
                            Guardar y Continuar
                        </Button>
                    </div>
                </form>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Select } from '../../components/ui/Select';
import { useAuth } from '../../contexts/AuthContext';
import { supabase } from '../../lib/supabase';
import { useToast } from '../../components/ui/Toast';

export function ProfilePage() {
    const { user, profile, refreshProfile } = useAuth();
    const { toast } = useToast();
    const [loading, setLoading] = useState(false);

    const [form, setForm] = useState({
        firstName: '',
        lastName: '',
        phone: '',
        channel: 'EMAIL'
    });

    useEffect(() => {
        if (profile) {
            setForm({
                firstName: profile.first_name || '',
                lastName: profile.last_name || '',
                phone: profile.phone || '',
                channel: profile.preferred_channel || 'EMAIL'
            });
        }
    }, [profile]);

    const handleSave = async () => {
        if (!user) return;
        setLoading(true);

        const phoneRegex = /^\+[1-9]\d{1,14}$/;
        if (form.phone && !phoneRegex.test(form.phone)) {
            toast({ title: 'Error de Validación', description: 'Formato de teléfono inválido. Use formato internacional (ej. +17205551234)', type: 'error' });
            setLoading(false);
            return;
        }

        try {
            const { error } = await supabase
                .from('profiles')
                .update({
                    first_name: form.firstName,
                    last_name: form.lastName,
                    phone: form.phone || null,
                    preferred_channel: form.channel
                })
                .eq('user_id', user.id);

            if (error) throw error;

            toast({ title: 'Perfil Actualizado', description: 'Tus datos han sido guardados exitosamente.', type: 'success' });
            await refreshProfile();
        } catch (error: any) {
            console.error('Error updating profile:', error);
            toast({ title: 'Error', description: error.message || 'No se pudo guardar la información', type: 'error' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-3xl mx-auto space-y-6 animate-in">
            <div>
                <h1 className="text-2xl font-bold">Mi Perfil</h1>
                <p className="text-muted-foreground">Administra tu información personal y preferencias de contacto.</p>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Datos Personales</CardTitle>
                    <CardDescription>Esta información será usada para contactarte sobre tus servicios.</CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                        <Input
                            label="Nombre(s)"
                            value={form.firstName}
                            onChange={(e) => setForm({ ...form, firstName: e.target.value })}
                        />
                        <Input
                            label="Apellido"
                            value={form.lastName}
                            onChange={(e) => setForm({ ...form, lastName: e.target.value })}
                        />
                    </div>
                    <Input
                        label="Correo Electrónico"
                        value={user?.email || ''}
                        disabled
                    />
                    <Input
                        label="Teléfono Móvil"
                        type="tel"
                        value={form.phone}
                        onChange={(e) => setForm({ ...form, phone: e.target.value })}
                        placeholder="+1 720 555 1234"
                        hint="Formato internacional, ej: +17205551234"
                    />
                    <Select
                        label="Canal de Contacto Preferido"
                        value={form.channel}
                        onChange={(e) => setForm({ ...form, channel: e.target.value })}
                        options={[
                            { value: 'EMAIL', label: 'Correo Electrónico' },
                            { value: 'SMS', label: 'Mensaje de Texto (SMS)' },
                            { value: 'WHATSAPP', label: 'WhatsApp' },
                            { value: 'TELEGRAM', label: 'Telegram' }
                        ]}
                    />
                </CardContent>
                <CardFooter className="flex justify-end">
                    <Button onClick={handleSave} loading={loading}>Guardar Cambios</Button>
                </CardFooter>
            </Card>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { Badge } from '../../components/ui/Badge';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import {
    ArrowLeft, Download,
    FileText, Zap, MapPin, Wrench, ShieldCheck,
    Clock, Check, X, Shield
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { useToast } from '../../components/ui/Toast';
import { TermsModal } from '../../components/ui/TermsModal';

export function RequestDetailPage() {
    const { id: requestId } = useParams();
    const { user } = useAuth();
    const { toast } = useToast();

    const [loading, setLoading] = useState(true);
    const [request, setRequest] = useState<any>(null);
    const [inspection, setInspection] = useState<any>(null);
    const [results, setResults] = useState<any[]>([]);
    const [quote, setQuote] = useState<any>(null);

    // Approval state
    const [showTerms, setShowTerms] = useState(false);
    const [acceptedTerms, setAcceptedTerms] = useState(false);
    const [signature, setSignature] = useState('');
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        if (user && requestId) {
            loadData();
        }
    }, [user, requestId]);

    async function loadData() {
        setLoading(true);
        try {
            const { data: reqData, error: reqError } = await supabase
                .from('service_requests')
                .select('*, vehicles(*), service_catalog(*), request_symptoms(symptom_tags(*))')
                .eq('id', requestId)
                .single();

            if (reqError) throw reqError;
            setRequest(reqData);

            const { data: inspData } = await supabase
                .from('inspections')
                .select('*')
                .eq('request_id', requestId)
                .maybeSingle();

            if (inspData) {
                setInspection(inspData);
                const { data: resData } = await supabase
                    .from('inspection_results')
                    .select('*, checklist_items(*)')
                    .eq('inspection_id', inspData.id)
                    .order('created_at', { ascending: true });
                setResults(resData || []);
            }

            // Fetch Quote
            const { data: qData } = await supabase
                .from('quotes')
                .select('*, quote_items(*)')
                .eq('request_id', requestId)
                .maybeSingle();

            setQuote(qData);

        } catch (err: any) {
            console.error('Error loading request details:', err);
        } finally {
            setLoading(false);
        }
    }

    const handleApproveQuote = async () => {
        if (!acceptedTerms || !signature.trim() || !quote || !user) return;

        setSubmitting(true);
        try {
            // 1. Create Approval Record
            const { error: appError } = await supabase
                .from('quote_approvals')
                .insert({
                    quote_id: quote.id,
                    approved_by_user_id: user.id,
                    signer_full_name: signature,
                    accepted_terms: true,
                    signer_user_agent: navigator.userAgent,
                });

            if (appError) throw appError;

            // Trigger will handle quote and request status updates to 'APPROVED'

            // 2. Notification
            await supabase.from('notifications_outbox').insert({
                recipient_user_id: user.id,
                recipient: user.email || '',
                channel: 'EMAIL', // Customer usually gets confirmation on email
                template_code: 'QUOTE_APPROVED',
                payload: {
                    data: {
                        name: request.profiles?.first_name || 'Cliente',
                        vehicle: `${request.vehicles.make} ${request.vehicles.model}`
                    }
                },
                status: 'PENDING'
            });

            toast({ title: 'Presupuesto Aprobado', description: 'El técnico comenzará con la reparación.', type: 'success' });
            loadData();
        } catch (err: any) {
            console.error('Error approving:', err);
            toast({ title: 'Error', description: 'No se pudo procesar la aprobación.', type: 'error' });
        } finally {
            setSubmitting(false);
        }
    };

    const handleRejectQuote = async () => {
        if (!quote || !user) return;
        const reason = window.prompt('Por favor, cuéntanos el motivo del rechazo (opcional):');

        setSubmitting(true);
        try {
            // 1. Update Status
            await supabase.from('quotes').update({ status: 'DECLINED' }).eq('id', quote.id);
            await supabase.from('service_requests').update({ status: 'DECLINED' }).eq('id', requestId);

            // 2. Notification
            await supabase.from('notifications_outbox').insert({
                recipient_user_id: user.id,
                recipient: user.email || '',
                channel: 'EMAIL',
                template_code: 'QUOTE_DECLINED',
                payload: {
                    data: {
                        name: request.profiles?.first_name || 'Cliente',
                        vehicle: `${request.vehicles.make} ${request.vehicles.model}`,
                        reason: reason || 'No especificado'
                    }
                },
                status: 'PENDING'
            });

            toast({ title: 'Presupuesto Rechazado', description: 'Lamentamos que no podamos proceder en esta ocasión.', type: 'info' });
            loadData();
        } catch (err) {
            toast({ title: 'Error', type: 'error' });
        } finally {
            setSubmitting(false);
        }
    };

    const handleCancelRequest = async () => {
        if (!window.confirm('¿Estás seguro de que deseas cancelar este servicio? Esta acción no se puede deshacer.')) return;

        setSubmitting(true);
        try {
            // Cancel Request
            await supabase.from('service_requests').update({ status: 'CANCELED' }).eq('id', requestId);

            // Cancel Appointments related
            await supabase.from('appointments').update({ status: 'CANCELED' }).eq('request_id', requestId);

            toast({ title: 'Servicio Cancelado', description: 'Tu solicitud ha sido cancelada exitosamente.', type: 'info' });
            loadData();
        } catch (err: any) {
            console.error('Error cancelling:', err);
            toast({ title: 'Error', description: 'No se pudo cancelar el servicio.', type: 'error' });
        } finally {
            setSubmitting(false);
        }
    };

    const getTimeline = () => {
        const stages = [
            { id: 'SUBMITTED', label: 'Solicitado', description: 'Recepción inicial' },
            { id: 'SCHEDULED', label: 'Programado', description: 'Técnico asignado' },
            { id: 'DIAGNOSED', label: 'Diagnosticado', description: 'Revisión técnica' },
            { id: 'QUOTED', label: 'Presupuestado', description: 'Esperando aprobación' },
            { id: 'APPROVED', label: 'Aprobado', description: 'En reparación' },
            { id: 'COMPLETED', label: 'Completado', description: '¡Listo!' }
        ];

        // Custom index finder
        const currentIdx = stages.findIndex(s => s.id === request?.status);
        const isCanceled = request?.status === 'CANCELED';
        const isDeclined = request?.status === 'DECLINED';

        return (
            <div className="flex justify-between items-center mb-10 overflow-x-auto pb-4 gap-4 px-2">
                {stages.map((stage, idx) => {
                    const isActive = idx <= currentIdx;
                    const isCurrent = idx === currentIdx;

                    return (
                        <div key={stage.id} className="flex flex-col items-center min-w-[80px] text-center relative">
                            {idx > 0 && (
                                <div className={`absolute top-4 right-1/2 w-full h-[2px] -z-10 ${idx <= currentIdx ? 'bg-primary' : 'bg-slate-200'}`} style={{ width: 'calc(100% + 2rem)', right: '50%' }}></div>
                            )}
                            <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 transition-all duration-500 ${isCurrent ? 'bg-primary border-primary text-white scale-110 shadow-lg shadow-primary/20' :
                                isActive ? 'bg-primary/10 border-primary text-primary' :
                                    'bg-white border-slate-200 text-slate-300'
                                }`}>
                                {isActive && !isCurrent ? <Check size={14} /> : <span>{idx + 1}</span>}
                            </div>
                            <span className={`text-[10px] font-bold mt-2 uppercase tracking-tight ${isActive ? 'text-slate-800' : 'text-slate-400'}`}>
                                {stage.label}
                            </span>
                        </div>
                    );
                })}
                {(isCanceled || isDeclined) && (
                    <div className="flex flex-col items-center min-w-[80px] text-center">
                        <div className="w-8 h-8 rounded-full bg-destructive border-2 border-destructive text-white flex items-center justify-center">
                            <X size={14} />
                        </div>
                        <span className="text-[10px] font-bold mt-2 uppercase text-destructive tracking-tight">
                            {isCanceled ? 'CANCELADO' : 'RECHAZADO'}
                        </span>
                    </div>
                )}
            </div>
        );
    };

    if (loading) return <div className="p-20 text-center">Cargando detalles...</div>;
    if (!request) return <div className="p-20 text-center text-muted-foreground">No se encontró la solicitud.</div>;

    const categories = Array.from(new Set(results.map(r => r.checklist_items?.category)));
    const allPhotos = results.reduce((acc: string[], curr) => [...acc, ...(curr.photo_urls || [])], []);

    return (
        <div className="max-w-5xl mx-auto space-y-6 animate-in pb-20 px-4">
            <Link to="/app/requests" className="inline-flex items-center text-sm text-muted-foreground hover:text-primary transition-colors">
                <ArrowLeft size={16} className="mr-1" /> Volver a mis servicios
            </Link>

            <div className="flex justify-between items-start flex-wrap gap-4">
                <div>
                    <h1 className="text-3xl font-bold flex items-center gap-3">
                        {request.vehicles?.year} {request.vehicles?.make} {request.vehicles?.model}
                        <Badge variant={request.status === 'APPROVED' ? 'success' : request.status === 'QUOTED' ? 'warning' : 'outline'}>
                            {request.status.replace('_', ' ')}
                        </Badge>
                    </h1>
                    <p className="text-muted-foreground mt-1 flex items-center gap-2">
                        <Wrench size={14} /> {request.service_catalog?.name} • ID: {requestId?.split('-')[0].toUpperCase()}
                    </p>
                </div>
                {inspection?.status === 'COMPLETED' && (
                    <Button variant="outline" onClick={() => window.print()}>
                        <Download size={16} className="mr-2" /> Descargar Reporte
                    </Button>
                )}
            </div>

            {getTimeline()}

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Main Content: Quote/Diagnosis & Checklist */}
                <div className="lg:col-span-2 space-y-6">

                    {/* Action Required: Quote Approval */}
                    {quote && quote.status === 'SENT' && (
                        <Card className="border-2 border-warning shadow-lg bg-warning/5 overflow-hidden animate-pulse-subtle">
                            <CardHeader className="bg-warning/10 border-b border-warning/20">
                                <CardTitle className="flex items-center gap-2 text-warning-foreground">
                                    <Zap size={20} /> Acción Requerida: Autorizar Reparación
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="p-6 space-y-6">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="p-4 bg-white rounded-lg border border-warning/20">
                                        <p className="text-[10px] font-bold text-muted-foreground uppercase mb-1">Total del Presupuesto</p>
                                        <p className="text-3xl font-bold text-primary">${quote.grand_total.toFixed(2)}</p>
                                    </div>
                                    <div className="p-4 bg-white rounded-lg border border-warning/20">
                                        <p className="text-[10px] font-bold text-muted-foreground uppercase mb-1">Tiempo Estimado (ETA)</p>
                                        <p className="text-xl font-bold flex items-center gap-2">
                                            <Clock size={18} className="text-primary" />
                                            {quote.eta_hours_min}-{quote.eta_hours_max} Horas
                                        </p>
                                        <p className="text-[10px] text-muted-foreground mt-1 italic">{quote.eta_notes || 'Una vez iniciados los trabajos.'}</p>
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    <h4 className="text-sm font-bold border-b pb-2">Desglose de Conceptos</h4>
                                    <div className="space-y-2">
                                        {quote.quote_items?.map((item: any) => (
                                            <div key={item.id} className="flex justify-between text-sm py-1 border-b border-dashed border-slate-200 last:border-0">
                                                <span>
                                                    <Badge variant="outline" className="mr-2 text-[8px] uppercase">{item.type}</Badge>
                                                    {item.description}
                                                    {item.quantity > 1 && <span className="text-muted-foreground text-[10px] ml-1">(x{item.quantity})</span>}
                                                </span>
                                                <span className={item.type === 'DISCOUNT' ? 'text-success font-bold' : ''}>
                                                    {item.type === 'DISCOUNT' ? '-' : ''}${Math.abs(item.total_price).toFixed(2)}
                                                </span>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="flex justify-between font-bold text-lg pt-2 text-slate-800">
                                        <span>Total Final</span>
                                        <span>${quote.grand_total.toFixed(2)}</span>
                                    </div>
                                </div>

                                {/* Approval Form */}
                                <div className="bg-white p-6 rounded-xl border-2 border-slate-100 space-y-4">
                                    <h4 className="font-bold flex items-center gap-2">
                                        <ShieldCheck size={18} className="text-success" />
                                        Firma de Autorización
                                    </h4>

                                    <div className="flex items-start gap-3 p-3 bg-slate-50 rounded-lg">
                                        <input
                                            type="checkbox"
                                            id="terms"
                                            className="mt-1 h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary"
                                            checked={acceptedTerms}
                                            onChange={(e) => setAcceptedTerms(e.target.checked)}
                                        />
                                        <label htmlFor="terms" className="text-xs text-slate-600 leading-tight">
                                            He leído y acepto los <button onClick={() => setShowTerms(true)} className="text-primary font-bold hover:underline">términos y condiciones</button> de Denver Mobile Auto Care. Entiendo que este es un presupuesto autorizado y el costo final puede variar si se encuentran adicionales.
                                        </label>
                                    </div>

                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-slate-500 uppercase">Nombre Completo (Firma Digital)</label>
                                        <Input
                                            placeholder="Escribe tu nombre tal como aparece en tu identificación"
                                            value={signature}
                                            onChange={(e) => setSignature(e.target.value)}
                                            className="font-signature text-lg italic"
                                        />
                                    </div>

                                    <div className="flex gap-3 pt-2">
                                        <Button
                                            variant="destructive"
                                            className="flex-1"
                                            onClick={handleRejectQuote}
                                            disabled={submitting}
                                        >
                                            <X size={16} className="mr-2" /> Rechazar
                                        </Button>
                                        <Button
                                            className="flex-[2] bg-success hover:bg-success/90 text-white"
                                            onClick={handleApproveQuote}
                                            disabled={!acceptedTerms || !signature.trim() || submitting}
                                        >
                                            <Check size={16} className="mr-2" /> Autorizar Reparación
                                        </Button>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* Approved Quote Summary */}
                    {quote && quote.status === 'APPROVED' && (
                        <Card className="border-success bg-success/5 overflow-hidden">
                            <CardHeader className="bg-success/10 border-b border-success/20 py-3">
                                <CardTitle className="text-sm font-bold text-success-foreground flex items-center gap-2">
                                    <Shield size={16} /> Presupuesto Autorizado
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="p-4 flex justify-between items-center flex-wrap gap-4">
                                <div>
                                    <p className="text-xs text-muted-foreground uppercase font-bold">Total del Proyecto</p>
                                    <p className="text-2xl font-bold text-slate-800">${quote.grand_total.toFixed(2)}</p>
                                </div>
                                <div className="text-right">
                                    <p className="text-xs text-muted-foreground uppercase font-bold">Estado</p>
                                    <Badge variant="success">TRABAJO EN PROCESO</Badge>
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* Diagnosis Result */}
                    {inspection?.status === 'COMPLETED' ? (
                        <Card className={`border-l-8 ${inspection.risk === 'HIGH' ? 'border-l-destructive bg-destructive/5' : inspection.risk === 'MED' ? 'border-l-amber-500 bg-amber-500/5' : 'border-l-success bg-success/5'}`}>
                            <CardHeader>
                                <div className="flex justify-between items-center mb-2">
                                    <Badge className={inspection.risk === 'HIGH' ? 'bg-destructive' : inspection.risk === 'MED' ? 'bg-amber-500' : 'bg-success'}>
                                        RIESGO: {inspection.risk}
                                    </Badge>
                                    <span className="text-xs text-muted-foreground flex items-center gap-1 italic">
                                        <ShieldCheck size={12} /> Diagnosticado por experto
                                    </span>
                                </div>
                                <CardTitle className="text-xl">Diagnóstico Técnico</CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <section>
                                    <h4 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-2">Hallazgos</h4>
                                    <p className="text-slate-700 bg-white/50 p-4 rounded-lg border border-slate-100 leading-relaxed">
                                        {inspection.findings || 'No se registraron hallazgos específicos.'}
                                    </p>
                                </section>
                                <section>
                                    <h4 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-2">Recomendación & Plan</h4>
                                    <p className="text-slate-700 bg-white/50 p-4 rounded-lg border border-slate-100 leading-relaxed">
                                        {inspection.recommendations || 'No se registraron recomendaciones.'}
                                    </p>
                                </section>
                                <div className="flex items-center gap-3 p-3 bg-white/80 rounded-lg border border-slate-100 text-xs text-slate-600">
                                    <Zap size={14} className="text-amber-500" />
                                    <span><strong>Preferencia de partes:</strong> {inspection.parts_by === 'SERVICE' ? 'Nosotros suministramos las refacciones premium.' : 'Mixto/Cliente por coordinar.'}</span>
                                </div>
                            </CardContent>
                        </Card>
                    ) : (
                        <Card className="bg-slate-50 border-dashed">
                            <CardContent className="p-12 text-center text-muted-foreground">
                                <Wrench size={40} className="mx-auto mb-4 opacity-20" />
                                <h3 className="text-lg font-medium text-slate-600">Inspección en curso</h3>
                                <p className="text-sm max-w-xs mx-auto mt-2">Nuestro técnico está revisando tu vehículo en este momento. Te notificaremos cuando el diagnóstico esté listo.</p>
                            </CardContent>
                        </Card>
                    )}

                    {/* Simple Checklist Summary */}
                    {results.length > 0 && (
                        <div className="space-y-4">
                            <h3 className="text-lg font-bold flex items-center gap-2">
                                <FileText size={20} className="text-primary" />
                                Resumen de Inspección Digital
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {categories.map(cat => (
                                    <Card key={cat} className="overflow-hidden">
                                        <div className="bg-slate-50 px-3 py-2 text-xs font-bold uppercase tracking-widest text-slate-500 border-b">
                                            {cat}
                                        </div>
                                        <CardContent className="p-3 space-y-2">
                                            {results.filter(r => r.checklist_items?.category === cat).map(r => (
                                                <div key={r.id} className="flex justify-between items-center text-sm">
                                                    <span className="text-slate-600">{r.checklist_items?.item_name}</span>
                                                    <Badge variant={r.status === 'OK' ? 'success' : r.status === 'ISSUE' ? 'destructive' : 'outline'} className="text-[10px] px-1.5 h-5">
                                                        {r.status}
                                                    </Badge>
                                                </div>
                                            ))}
                                        </CardContent>
                                    </Card>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                {/* Sidebar: Media & Stats */}
                <div className="space-y-6">
                    {/* Media Gallery */}
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm uppercase text-slate-400">Evidencia (Fotos)</CardTitle>
                        </CardHeader>
                        <CardContent>
                            {allPhotos.length > 0 ? (
                                <div className="grid grid-cols-2 gap-2">
                                    {allPhotos.map((url: string, idx: number) => (
                                        <div key={idx} className="aspect-square rounded-md overflow-hidden border bg-slate-100 cursor-pointer hover:opacity-80 transition-opacity">
                                            <img src={url} alt={`Evidencia ${idx}`} className="w-full h-full object-cover" />
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="text-center py-10 text-xs text-muted-foreground bg-slate-50 rounded-lg border-2 border-dashed">
                                    No hay fotos adjuntas todavía.
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    {/* Service Info */}
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm uppercase text-slate-400">Información del Servicio</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="flex items-start gap-3">
                                <MapPin size={16} className="text-primary mt-1 shrink-0" />
                                <div className="text-sm">
                                    <p className="font-medium">Ubicación de Visita</p>
                                    <p className="text-muted-foreground italic text-xs leading-relaxed">Las coordenadas y dirección exacta están protegidas para privacidad del técnico.</p>
                                </div>
                            </div>
                            <div className="pt-4 border-t flex items-center justify-between text-sm">
                                <span className="text-muted-foreground">Estado Global</span>
                                <Badge variant="secondary">{request.status}</Badge>
                            </div>

                            {['SUBMITTED', 'SCHEDULED', 'DIAGNOSED', 'QUOTED'].includes(request.status) && (
                                <div className="pt-4 border-t">
                                    <Button
                                        variant="outline"
                                        className="w-full text-destructive border-destructive/20 hover:bg-destructive/5"
                                        onClick={handleCancelRequest}
                                        loading={submitting}
                                    >
                                        <X size={16} className="mr-2" /> Cancelar Servicio
                                    </Button>
                                    <p className="text-[10px] text-muted-foreground text-center mt-2 italic">
                                        Solo puedes cancelar antes de que inicie la reparación.
                                    </p>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>

            <TermsModal isOpen={showTerms} onClose={() => setShowTerms(false)} />
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Card, CardContent } from '../../components/ui/Card';
import { Badge } from '../../components/ui/Badge';
import { Button } from '../../components/ui/Button';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../../components/ui/Table';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { useToast } from '../../components/ui/Toast';
import { Calendar, Wrench, PlusCircle, Inbox } from 'lucide-react';

const STATUS_BADGE: Record<string, 'warning' | 'success' | 'destructive' | 'secondary' | 'outline'> = {
    SUBMITTED: 'warning',
    SCHEDULED: 'secondary',
    DIAGNOSED: 'secondary',
    QUOTED: 'warning',
    APPROVED: 'success',
    COMPLETED: 'success',
    CANCELED: 'destructive',
    DECLINED: 'destructive',
};

const STATUS_LABEL: Record<string, string> = {
    SUBMITTED: 'Solicitado',
    SCHEDULED: 'Programado',
    DIAGNOSED: 'Diagnosticado',
    QUOTED: 'Pendiente Cotización',
    APPROVED: 'Aprobado',
    COMPLETED: 'Completado',
    CANCELED: 'Cancelado',
    DECLINED: 'Rechazado',
};

export function RequestsPage() {
    const { user } = useAuth();
    const { toast } = useToast();
    const [requests, setRequests] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (user) loadRequests();
    }, [user]);

    async function loadRequests() {
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('service_requests')
                .select('*, vehicles(make, model, year), service_catalog(name)')
                .eq('customer_id', user!.id)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setRequests(data || []);
        } catch (err: any) {
            console.error('Error loading requests:', err);
            toast({ title: 'Error', description: 'No se pudieron cargar tus solicitudes.', type: 'error' });
        } finally {
            setLoading(false);
        }
    }

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[40vh] gap-4">
                <div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <p className="text-muted-foreground text-sm">Cargando tus solicitudes...</p>
            </div>
        );
    }

    return (
        <div className="space-y-6 animate-in">
            <div className="flex justify-between items-center flex-wrap gap-4">
                <div>
                    <h1 className="text-2xl font-bold">Mis Solicitudes</h1>
                    <p className="text-muted-foreground">Historial de servicios y presupuestos actuales.</p>
                </div>
                <Link to="/app/schedule">
                    <Button className="gap-2">
                        <PlusCircle size={16} /> Agendar Nuevo
                    </Button>
                </Link>
            </div>

            {requests.length === 0 ? (
                <Card>
                    <CardContent className="py-20 text-center flex flex-col items-center gap-4 text-muted-foreground">
                        <Inbox size={48} className="opacity-20" />
                        <div>
                            <h3 className="font-semibold text-slate-600 text-lg">Sin solicitudes aún</h3>
                            <p className="text-sm mt-1">Cuando agendes tu primer servicio aparecerá aquí.</p>
                        </div>
                        <Link to="/app/schedule">
                            <Button variant="outline" className="mt-2 gap-2">
                                <Calendar size={16} /> Agendar mi primer servicio
                            </Button>
                        </Link>
                    </CardContent>
                </Card>
            ) : (
                <Card>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Vehículo</TableHead>
                                <TableHead>Servicio</TableHead>
                                <TableHead>Fecha</TableHead>
                                <TableHead>Estado</TableHead>
                                <TableHead></TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {requests.map((req) => (
                                <TableRow key={req.id}>
                                    <TableCell className="font-medium flex items-center gap-2">
                                        <Wrench size={14} className="text-slate-400 shrink-0" />
                                        {req.vehicles
                                            ? `${req.vehicles.year} ${req.vehicles.make} ${req.vehicles.model}`
                                            : '—'}
                                    </TableCell>
                                    <TableCell>{req.service_catalog?.name || req.description || '—'}</TableCell>
                                    <TableCell className="text-sm text-muted-foreground">
                                        {new Date(req.created_at).toLocaleDateString('es-US', {
                                            day: '2-digit', month: 'short', year: 'numeric'
                                        })}
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant={STATUS_BADGE[req.status] || 'outline'}>
                                            {STATUS_LABEL[req.status] || req.status}
                                        </Badge>
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <Link to={`/app/requests/${req.id}`}>
                                            <Button variant="ghost" size="sm">Ver Detalles</Button>
                                        </Link>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </Card>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useSearchParams, useNavigate, Link } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from '../../components/ui/Card';
import { Stepper } from '../../components/ui/Stepper';
import type { Step } from '../../components/ui/Stepper';
import { Button } from '../../components/ui/Button';
import { Select } from '../../components/ui/Select';
import { Input } from '../../components/ui/Input';
import { useToast } from '../../components/ui/Toast';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { MapPin, Calendar, Clock, DollarSign, CheckCircle, ArrowRight } from 'lucide-react';

const steps: Step[] = [
    { id: '1', title: 'Ubicación', description: '¿Dónde está el vehículo?' },
    { id: '2', title: 'Fecha & Hora', description: '¿Cuándo vamos?' },
    { id: '3', title: 'Resumen', description: 'Revisa tu cita' }
];

const TIME_SLOTS = [
    { label: 'Mañana (09:00 - 12:00)', value: '09:00-12:00', start: '09:00', end: '12:00' },
    { label: 'Mediodía (12:00 - 15:00)', value: '12:00-15:00', start: '12:00', end: '15:00' },
    { label: 'Tarde (15:00 - 18:00)', value: '15:00-18:00', start: '15:00', end: '18:00' },
];

export function SchedulePage() {
    const [searchParams] = useSearchParams();
    const requestId = searchParams.get('request_id');
    const { user, profile } = useAuth();
    const { toast } = useToast();
    const navigate = useNavigate();

    const [currentStep, setCurrentStep] = useState(0);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [confirmed, setConfirmed] = useState(false);

    // Data from DB
    const [request, setRequest] = useState<any>(null);
    const [config, setConfig] = useState<any>(null);

    // Form State
    const [address, setAddress] = useState({
        line1: '',
        line2: '',
        zip: '',
        city: 'Denver',
        state: 'CO'
    });
    const [distanceMiles, setDistanceMiles] = useState(10);
    const [selectedDate, setSelectedDate] = useState('');
    const [selectedSlot, setSelectedSlot] = useState(TIME_SLOTS[0].value);

    // Costs
    const visitFee = 30.00;
    const distancePricing = config?.distance_pricing_per_mile || 1.5;
    const distanceSurcharge = distanceMiles * distancePricing;
    const totalCost = visitFee + distanceSurcharge;

    useEffect(() => {
        async function loadData() {
            if (!requestId) {
                toast({ title: 'Error', description: 'No se encontró el ID de la solicitud.', type: 'error' });
                navigate('/app/requests');
                return;
            }

            try {
                // Fetch Request
                const { data: reqData, error: reqError } = await supabase
                    .from('service_requests')
                    .select('*, vehicles(*), service_catalog(*)')
                    .eq('id', requestId)
                    .single();

                if (reqError) throw reqError;
                setRequest(reqData);

                // Fetch Config
                const { data: confData } = await supabase
                    .from('app_config')
                    .select('*')
                    .limit(1)
                    .single();

                if (confData) setConfig(confData);

            } catch (err: any) {
                console.error('Error loading schedule data:', err);
                toast({ title: 'Error', description: 'No se pudo cargar la información.', type: 'error' });
            } finally {
                setLoading(false);
            }
        }

        loadData();
    }, [requestId, navigate, toast]);

    const handleNext = () => {
        if (currentStep === 0) {
            if (!address.line1 || !address.zip) {
                toast({ title: 'Campo requerido', description: 'Por favor ingresa la dirección y ZIP.', type: 'warning' });
                return;
            }
        }
        if (currentStep === 1) {
            if (!selectedDate) {
                toast({ title: 'Campo requerido', description: 'Por favor selecciona una fecha.', type: 'warning' });
                return;
            }
            // Check if date is in the future
            const today = new Date().toISOString().split('T')[0];
            if (selectedDate < today) {
                toast({ title: 'Fecha inválida', description: 'La fecha debe ser hoy o en el futuro.', type: 'warning' });
                return;
            }
        }

        if (currentStep < steps.length - 1) {
            setCurrentStep(prev => prev + 1);
        } else {
            handleConfirm();
        }
    };

    const handleBack = () => {
        if (currentStep > 0) setCurrentStep(prev => prev - 1);
    };

    const handleConfirm = async () => {
        setSubmitting(true);
        try {
            const slot = TIME_SLOTS.find(s => s.value === selectedSlot);
            const startDateTime = `${selectedDate}T${slot?.start}:00Z`;
            const endDateTime = `${selectedDate}T${slot?.end}:00Z`;

            // 1. Create Appointment
            const { error: apptError } = await supabase
                .from('appointments')
                .insert({
                    request_id: requestId,
                    scheduled_start: startDateTime,
                    scheduled_end: endDateTime,
                    address: `${address.line1}${address.line2 ? ', ' + address.line2 : ''}`,
                    city: address.city,
                    state: address.state,
                    zip: address.zip,
                    distance_miles: distanceMiles,
                    visit_fee: visitFee,
                    distance_surcharge: distanceSurcharge,
                    total_visit_cost: totalCost,
                    customer_channel: profile?.preferred_channel || 'EMAIL',
                    status: 'SCHEDULED'
                });

            if (apptError) throw apptError;

            // 2. Update Service Request Status
            const { error: reqUpdateError } = await supabase
                .from('service_requests')
                .update({ status: 'SCHEDULED' })
                .eq('id', requestId);

            if (reqUpdateError) throw reqUpdateError;

            // 3. Queue Notification (Simulated)
            await supabase
                .from('notifications_outbox')
                .insert({
                    recipient_user_id: user?.id,
                    recipient: user?.email || profile?.phone || '',
                    channel: profile?.preferred_channel || 'EMAIL',
                    template_code: 'APPOINTMENT_CONFIRMED',
                    payload: {
                        data: {
                            name: profile?.first_name || 'Cliente',
                            date: selectedDate,
                            time: slot?.label
                        }
                    },
                    status: 'PENDING'
                });

            setConfirmed(true);
            toast({ title: '¡Éxito!', description: 'Tu cita ha sido confirmada.', type: 'success' });

        } catch (err: any) {
            console.error('Error confirming appointment:', err);
            toast({ title: 'Error', description: 'No se pudo confirmar la cita.', type: 'error' });
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[50vh] gap-4">
                <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <p className="text-muted-foreground">Cargando detalles de tu solicitud...</p>
            </div>
        );
    }

    if (confirmed) {
        return (
            <div className="max-w-2xl mx-auto py-12 px-4 animate-in">
                <Card className="text-center p-8 border-success/20 shadow-xl rounded-2xl">
                    <div className="w-20 h-20 bg-success/10 text-success rounded-full flex items-center justify-center mx-auto mb-6">
                        <CheckCircle size={48} />
                    </div>
                    <CardHeader>
                        <CardTitle className="text-3xl font-bold">¡Cita Confirmada!</CardTitle>
                        <p className="text-muted-foreground mt-2">
                            Hemos recibido tu programación. Un técnico te contactará el día del servicio.
                        </p>
                    </CardHeader>
                    <CardContent className="mt-8">
                        <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 text-left space-y-4">
                            <h4 className="font-semibold text-slate-700 uppercase text-xs tracking-wider">Resumen de la Cita</h4>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="flex items-center gap-3">
                                    <Calendar className="text-primary" size={18} />
                                    <div>
                                        <p className="text-xs text-slate-500">Fecha</p>
                                        <p className="font-medium">{selectedDate}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <Clock className="text-primary" size={18} />
                                    <div>
                                        <p className="text-xs text-slate-500">Horario</p>
                                        <p className="font-medium">{TIME_SLOTS.find(s => s.value === selectedSlot)?.label.split(' ')[0]}</p>
                                    </div>
                                </div>
                                <div className="col-span-2 flex items-center gap-3">
                                    <MapPin className="text-primary" size={18} />
                                    <div>
                                        <p className="text-xs text-slate-500">Dirección</p>
                                        <p className="font-medium">{address.line1}, {address.city}, {address.state}</p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </CardContent>
                    <CardFooter className="mt-8 flex flex-col sm:flex-row gap-4 justify-center">
                        <Link to={`/app/requests/${requestId}`} className="w-full sm:w-auto">
                            <Button className="w-full sm:w-auto">Ver Solicitud</Button>
                        </Link>
                        <Link to="/app" className="w-full sm:w-auto">
                            <Button variant="outline" className="w-full sm:w-auto">Ir al Dashboard</Button>
                        </Link>
                    </CardFooter>
                </Card>
            </div>
        );
    }

    return (
        <div className="max-w-4xl mx-auto space-y-8 animate-in pb-12">
            <div>
                <h1 className="text-2xl font-bold">Agendar Servicio</h1>
                <p className="text-muted-foreground">Completa los detalles para que un técnico visite tu vehículo.</p>
                {request && (
                    <div className="mt-4 flex items-center gap-2 text-sm bg-primary/5 text-primary-hover p-3 rounded-lg border border-primary/10">
                        <ArrowRight size={16} />
                        <span>Programando: <strong>{request.service_catalog?.name}</strong> para <strong>{request.vehicles?.make} {request.vehicles?.model}</strong></span>
                    </div>
                )}
            </div>

            <Stepper steps={steps} currentStep={currentStep} />

            <Card className="mt-8 shadow-lg border-slate-200">
                <CardHeader className="border-b bg-slate-50/50">
                    <CardTitle className="text-lg">
                        {currentStep === 0 && '¿Dónde se encuentra el vehículo?'}
                        {currentStep === 1 && '¿Cuándo quieres que vayamos?'}
                        {currentStep === 2 && 'Confirmación de detalles'}
                    </CardTitle>
                </CardHeader>
                <CardContent className="p-6">

                    {currentStep === 0 && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <Input
                                    label="Calle y Número (Address Line 1)"
                                    placeholder="Ej. 123 Main St"
                                    value={address.line1}
                                    onChange={e => setAddress({ ...address, line1: e.target.value })}
                                    required
                                />
                                <Input
                                    label="Depto / Suite / Notas extra"
                                    placeholder="Opcional"
                                    value={address.line2}
                                    onChange={e => setAddress({ ...address, line2: e.target.value })}
                                />
                                <Input
                                    label="ZIP Code"
                                    placeholder="80204"
                                    value={address.zip}
                                    onChange={e => setAddress({ ...address, zip: e.target.value })}
                                    required
                                />
                                <div className="grid grid-cols-2 gap-2">
                                    <Input label="Ciudad" value={address.city} disabled />
                                    <Select
                                        label="Estado"
                                        value={address.state}
                                        options={[{ label: 'Colorado', value: 'CO' }]}
                                        disabled
                                    />
                                </div>
                            </div>

                            <div className="pt-6 border-t border-slate-100">
                                <label className="text-sm font-medium block mb-4 flex items-center gap-2">
                                    <MapPin size={16} className="text-primary" />
                                    Distancia estimada desde el centro (Millas)
                                </label>
                                <div className="space-y-4">
                                    <div className="flex justify-between text-xs text-muted-foreground font-medium">
                                        <span>0 mi</span>
                                        <span className="text-primary text-lg">{distanceMiles} mi</span>
                                        <span>50 mi</span>
                                    </div>
                                    <input
                                        type="range"
                                        min="0"
                                        max="50"
                                        step="1"
                                        value={distanceMiles}
                                        onChange={e => setDistanceMiles(parseInt(e.target.value))}
                                        className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-primary"
                                    />
                                    <p className="text-[10px] text-slate-400 italic">
                                        * Estimado de distancia para calcular el recargo por traslado.
                                    </p>
                                </div>
                            </div>
                        </div>
                    )}

                    {currentStep === 1 && (
                        <div className="space-y-6 max-w-md mx-auto">
                            <Input
                                label="Fecha de la visita"
                                type="date"
                                value={selectedDate}
                                onChange={e => setSelectedDate(e.target.value)}
                                min={new Date().toISOString().split('T')[0]}
                                required
                            />
                            <Select
                                label="Franja horaria preferida"
                                value={selectedSlot}
                                onChange={e => setSelectedSlot(e.target.value)}
                                options={TIME_SLOTS.map(t => ({ label: t.label, value: t.value }))}
                            />
                            <div className="bg-blue-50 p-4 rounded-lg flex gap-3 text-blue-700 text-sm border border-blue-100 mt-6">
                                <Clock size={18} className="shrink-0" />
                                <p>
                                    Nuestros técnicos operan en ventanas de 3 horas para dar flexibilidad ante el tráfico y trabajos previos.
                                </p>
                            </div>
                        </div>
                    )}

                    {currentStep === 2 && (
                        <div className="space-y-6">
                            <div className="bg-slate-50 rounded-xl border border-slate-200 divide-y divide-slate-200 overflow-hidden">
                                <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-y-4 gap-x-8">
                                    <div className="flex items-start gap-3">
                                        <MapPin className="text-slate-400 mt-1" size={18} />
                                        <div>
                                            <p className="text-[10px] uppercase font-bold text-slate-400">Ubicación</p>
                                            <p className="text-sm">{address.line1}, {address.city}, {address.state} {address.zip}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-start gap-3">
                                        <Calendar className="text-slate-400 mt-1" size={18} />
                                        <div>
                                            <p className="text-[10px] uppercase font-bold text-slate-400">Programación</p>
                                            <p className="text-sm">{selectedDate} - {TIME_SLOTS.find(s => s.value === selectedSlot)?.label.split(' ')[0]}</p>
                                        </div>
                                    </div>
                                </div>

                                <div className="p-4 space-y-3">
                                    <h4 className="text-xs font-bold text-slate-400 uppercase flex items-center gap-2">
                                        <DollarSign size={14} /> Desglose de Costos de Visita
                                    </h4>
                                    <div className="space-y-2">
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-600">Cargo base de visita</span>
                                            <span className="font-medium">${visitFee.toFixed(2)}</span>
                                        </div>
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-600">Recargo por distancia ({distanceMiles} mi x ${distancePricing.toFixed(2)})</span>
                                            <span className="font-medium">${distanceSurcharge.toFixed(2)}</span>
                                        </div>
                                        <div className="pt-2 border-t border-slate-200 flex justify-between font-bold text-slate-800">
                                            <span>Total costo de visita</span>
                                            <span className="text-lg text-primary">${totalCost.toFixed(2)}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="p-4 bg-amber-50 rounded-lg border border-amber-100 text-amber-800 text-xs leading-relaxed">
                                <p className="font-bold mb-1">Nota importante:</p>
                                Este total corresponde únicamente al traslado y diagnóstico inicial. El costo del servicio (mano de obra y partes) se cotizará después de la inspección física del técnico.
                            </div>
                        </div>
                    )}

                </CardContent>
                <div className="flex justify-between p-6 pt-0">
                    <Button variant="outline" onClick={handleBack} disabled={currentStep === 0}>Atrás</Button>
                    <Button onClick={handleNext} loading={submitting}>
                        {currentStep === steps.length - 1 ? 'Confirmar Cita' : 'Siguiente'}
                    </Button>
                </div>
            </Card>
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Plus, Trash2, Edit2, History, Car } from 'lucide-react';
import { Modal } from '../../components/ui/Modal';
import { Input } from '../../components/ui/Input';
import { Select } from '../../components/ui/Select';
import { useToast } from '../../components/ui/Toast';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { Timeline, type TimelineItem } from '../../components/ui/Timeline';

interface Vehicle {
    id: string;
    year: number;
    make: string;
    model: string;
    trim: string | null;
    powertrain: 'GAS' | 'HYBRID' | 'EV' | 'DIESEL';
    odometer: number | null;
    notes: string | null;
    created_at: string;
}

export function VehiclesPage() {
    const { user } = useAuth();
    const { toast } = useToast();
    const [vehicles, setVehicles] = useState<Vehicle[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);
    const [editingVehicle, setEditingVehicle] = useState<Vehicle | null>(null);
    const [vehicleToDelete, setVehicleToDelete] = useState<string | null>(null);
    const [selectedVehicleHistory, setSelectedVehicleHistory] = useState<TimelineItem[]>([]);
    const [historyLoading, setHistoryLoading] = useState(false);

    const [form, setForm] = useState({
        year: new Date().getFullYear(),
        make: '',
        model: '',
        trim: '',
        powertrain: 'GAS' as 'GAS' | 'HYBRID' | 'EV' | 'DIESEL',
        odometer: '',
        notes: ''
    });

    const fetchVehicles = useCallback(async () => {
        if (!user) return;
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('vehicles')
                .select('*')
                .eq('owner_user_id', user.id)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setVehicles(data || []);
        } catch (error: any) {
            toast({ title: 'Error', description: error.message, type: 'error' });
        } finally {
            setLoading(false);
        }
    }, [user, toast]);

    useEffect(() => {
        fetchVehicles();
    }, [fetchVehicles]);

    const handleOpenModal = (vehicle?: Vehicle) => {
        if (vehicle) {
            setEditingVehicle(vehicle);
            setForm({
                year: vehicle.year,
                make: vehicle.make,
                model: vehicle.model,
                trim: vehicle.trim || '',
                powertrain: vehicle.powertrain,
                odometer: vehicle.odometer?.toString() || '',
                notes: vehicle.notes || ''
            });
        } else {
            setEditingVehicle(null);
            setForm({
                year: new Date().getFullYear(),
                make: '',
                model: '',
                trim: '',
                powertrain: 'GAS',
                odometer: '',
                notes: ''
            });
        }
        setIsModalOpen(true);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;

        const vehicleData = {
            owner_user_id: user.id,
            year: form.year,
            make: form.make,
            model: form.model,
            trim: form.trim || null,
            powertrain: form.powertrain,
            odometer: form.odometer ? parseInt(form.odometer) : null,
            notes: form.notes || null
        };

        try {
            if (editingVehicle) {
                const { error } = await supabase
                    .from('vehicles')
                    .update(vehicleData)
                    .eq('id', editingVehicle.id);
                if (error) throw error;
                toast({ title: 'Actualizado', description: 'Vehículo actualizado con éxito.', type: 'success' });
            } else {
                const { error } = await supabase
                    .from('vehicles')
                    .insert(vehicleData);
                if (error) throw error;
                toast({ title: 'Creado', description: 'Vehículo agregado con éxito.', type: 'success' });
            }
            setIsModalOpen(false);
            fetchVehicles();
        } catch (error: any) {
            toast({ title: 'Error', description: error.message, type: 'error' });
        }
    };

    const handleDelete = async () => {
        if (!vehicleToDelete) return;
        try {
            const { error } = await supabase
                .from('vehicles')
                .delete()
                .eq('id', vehicleToDelete);
            if (error) throw error;
            toast({ title: 'Eliminado', description: 'Vehículo eliminado con éxito.', type: 'success' });
            setIsDeleteModalOpen(false);
            fetchVehicles();
        } catch (error: any) {
            toast({ title: 'Error', description: error.message, type: 'error' });
        }
    };

    const fetchHistory = async (vehicle: Vehicle) => {
        setHistoryLoading(true);
        setIsHistoryModalOpen(true);
        try {
            // Fetch requests and their inspections
            const { data, error } = await supabase
                .from('service_requests')
                .select(`
                    id,
                    status,
                    created_at,
                    service_catalog (name),
                    inspections (findings, risk)
                `)
                .eq('vehicle_id', vehicle.id)
                .order('created_at', { ascending: false });

            if (error) throw error;

            const timelineItems: TimelineItem[] = (data || []).map((req: any) => ({
                id: req.id,
                title: req.service_catalog?.name || 'Servicio General',
                description: req.inspections?.[0]?.findings || `Estado: ${req.status}`,
                date: new Date(req.created_at).toLocaleDateString(),
                status: req.status === 'COMPLETED' ? 'success' : 'default'
            }));

            setSelectedVehicleHistory(timelineItems);
        } catch (error: any) {
            toast({ title: 'Error', description: 'No se pudo cargar el historial.', type: 'error' });
        } finally {
            setHistoryLoading(false);
        }
    };

    return (
        <div className="space-y-6 animate-in">
            <div className="flex justify-between items-center flex-wrap gap-4">
                <div>
                    <h1 className="text-2xl font-bold">Mis Vehículos</h1>
                    <p className="text-muted-foreground">Administra los autos asociados a tu cuenta.</p>
                </div>
                <Button onClick={() => handleOpenModal()}>
                    <Plus size={16} className="mr-2" /> Agregar Vehículo
                </Button>
            </div>

            {loading ? (
                <div className="flex justify-center py-12 text-slate-400">Cargando vehículos...</div>
            ) : vehicles.length === 0 ? (
                <Card className="p-12 text-center border-dashed">
                    <div className="flex flex-col items-center gap-4">
                        <div className="w-16 h-16 bg-slate-50 flex items-center justify-center rounded-full text-slate-300">
                            <Car size={32} />
                        </div>
                        <p className="text-slate-500">Aún no has agregado ningún vehículo.</p>
                        <Button variant="outline" onClick={() => handleOpenModal()}>Agregar el primero</Button>
                    </div>
                </Card>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {vehicles.map((vehicle) => (
                        <Card key={vehicle.id} className="group hover:border-primary/30 transition-colors">
                            <CardHeader className="pb-2">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <CardTitle>{vehicle.make} {vehicle.model}</CardTitle>
                                        <CardDescription>{vehicle.year} • {vehicle.powertrain}</CardDescription>
                                    </div>
                                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <Button size="icon" variant="ghost" className="h-8 w-8" onClick={() => handleOpenModal(vehicle)}>
                                            <Edit2 size={14} />
                                        </Button>
                                        <Button size="icon" variant="ghost" className="h-8 w-8 text-destructive" onClick={() => {
                                            setVehicleToDelete(vehicle.id);
                                            setIsDeleteModalOpen(true);
                                        }}>
                                            <Trash2 size={14} />
                                        </Button>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="space-y-2 text-sm">
                                <p className="text-slate-600">
                                    <span className="font-medium text-slate-900">Millas:</span> {vehicle.odometer ? `${vehicle.odometer.toLocaleString()} mi` : 'No registrado'}
                                </p>
                                {vehicle.trim && (
                                    <p className="text-slate-600">
                                        <span className="font-medium text-slate-900">Versión:</span> {vehicle.trim}
                                    </p>
                                )}
                            </CardContent>
                            <CardFooter className="pt-2 border-t mt-4">
                                <Button variant="ghost" fullWidth size="sm" onClick={() => fetchHistory(vehicle)}>
                                    <History size={14} className="mr-2" /> Ver Historial
                                </Button>
                            </CardFooter>
                        </Card>
                    ))}
                </div>
            )}

            {/* Form Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={editingVehicle ? "Editar Vehículo" : "Agregar Nuevo Vehículo"}
            >
                <form className="space-y-4" onSubmit={handleSubmit}>
                    <div className="grid grid-cols-2 gap-4">
                        <Input
                            label="Año"
                            type="number"
                            min="1900"
                            max={new Date().getFullYear() + 1}
                            value={form.year}
                            onChange={(e) => setForm({ ...form, year: parseInt(e.target.value) })}
                            required
                        />
                        <Input
                            label="Marca"
                            placeholder="Ej. Toyota"
                            value={form.make}
                            onChange={(e) => setForm({ ...form, make: e.target.value })}
                            required
                        />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <Input
                            label="Modelo"
                            placeholder="Ej. Camry"
                            value={form.model}
                            onChange={(e) => setForm({ ...form, model: e.target.value })}
                            required
                        />
                        <Input
                            label="Versión / Trim"
                            placeholder="Ej. SE"
                            value={form.trim}
                            onChange={(e) => setForm({ ...form, trim: e.target.value })}
                        />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <Select
                            label="Motorización"
                            value={form.powertrain}
                            onChange={(e) => setForm({ ...form, powertrain: e.target.value as any })}
                            options={[
                                { value: 'GAS', label: 'Gasolina' },
                                { value: 'HYBRID', label: 'Híbrido' },
                                { value: 'EV', label: 'Eléctrico' },
                                { value: 'DIESEL', label: 'Diesel' }
                            ]}
                        />
                        <Input
                            label="Odómetro (Millas)"
                            type="number"
                            value={form.odometer}
                            onChange={(e) => setForm({ ...form, odometer: e.target.value })}
                        />
                    </div>
                    <Input
                        label="Notas Adicionales"
                        value={form.notes}
                        onChange={(e) => setForm({ ...form, notes: e.target.value })}
                    />
                    <div className="pt-4 flex justify-end gap-2">
                        <Button variant="ghost" type="button" onClick={() => setIsModalOpen(false)}>Cancelar</Button>
                        <Button type="submit">Guardar</Button>
                    </div>
                </form>
            </Modal>

            {/* Delete Confirmation Modal */}
            <Modal
                isOpen={isDeleteModalOpen}
                onClose={() => setIsDeleteModalOpen(false)}
                title="¿Eliminar vehículo?"
            >
                <div className="py-4 text-slate-600">
                    Esta acción no se puede deshacer. Se perderá el acceso al historial vinculado a este vehículo desde el perfil.
                </div>
                <div className="flex justify-end gap-2 pt-4">
                    <Button variant="ghost" onClick={() => setIsDeleteModalOpen(false)}>Cancelar</Button>
                    <Button variant="destructive" onClick={handleDelete}>Confirmar Eliminación</Button>
                </div>
            </Modal>

            {/* History Modal */}
            <Modal
                isOpen={isHistoryModalOpen}
                onClose={() => setIsHistoryModalOpen(false)}
                title="Historial de Salud (Health History)"
            >
                {historyLoading ? (
                    <div className="py-8 text-center text-slate-400">Cargando historial...</div>
                ) : selectedVehicleHistory.length === 0 ? (
                    <div className="py-8 text-center text-slate-500 italic">No hay historial para este vehículo aún.</div>
                ) : (
                    <div className="max-h-[60vh] overflow-y-auto pr-2">
                        <Timeline items={selectedVehicleHistory} />
                    </div>
                )}
                <div className="flex justify-end pt-6">
                    <Button variant="outline" onClick={() => setIsHistoryModalOpen(false)}>Cerrar</Button>
                </div>
            </Modal>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Badge } from '../../components/ui/Badge';
import {
    ArrowLeft, CheckSquare, UploadCloud, AlertTriangle,
    CheckCircle2, MinusCircle, FileText, Printer, Save, DollarSign
} from 'lucide-react';
import { useToast } from '../../components/ui/Toast';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';

export function TechRequestDetailPage() {
    const { id: requestId } = useParams();
    const { user } = useAuth();
    const { toast } = useToast();
    const navigate = useNavigate();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [loading, setLoading] = useState(true);
    const [request, setRequest] = useState<any>(null);
    const [inspection, setInspection] = useState<any>(null);
    const [results, setResults] = useState<any[]>([]);
    const [checklistItems, setChecklistItems] = useState<any[]>([]);
    const [uploading, setUploading] = useState(false);

    // Diagnosis state
    const [diagnosis, setDiagnosis] = useState({
        risk: 'LOW',
        findings: '',
        recommendations: '',
        parts_by: 'SERVICE'
    });

    // Quote state
    const [quoteItems, setQuoteItems] = useState<any[]>([]);
    const [eta, setEta] = useState({
        hours_min: 2,
        hours_max: 4,
        notes: ''
    });
    const [existingQuote, setExistingQuote] = useState<any>(null);

    useEffect(() => {
        loadData();
    }, [requestId]);

    async function loadData() {
        setLoading(true);
        try {
            // 1. Fetch Request & Related
            const { data: reqData, error: reqError } = await supabase
                .from('service_requests')
                .select('*, profiles(*), vehicles(*), service_catalog(*), request_symptoms(symptom_tags(*))')
                .eq('id', requestId)
                .single();

            if (reqError) throw reqError;
            setRequest(reqData);

            // 2. Fetch Active Inspection for this Tech/Request
            const { data: inspData } = await supabase
                .from('inspections')
                .select('*')
                .eq('request_id', requestId)
                .eq('tech_user_id', user?.id)
                .single();

            if (inspData) {
                setInspection(inspData);
                // Load Results
                const { data: resData } = await supabase
                    .from('inspection_results')
                    .select('*, checklist_items(*)')
                    .eq('inspection_id', inspData.id)
                    .order('created_at', { ascending: true });
                setResults(resData || []);

                // Populate diagnosis fields
                setDiagnosis({
                    risk: inspData.risk || 'LOW',
                    findings: inspData.findings || '',
                    recommendations: inspData.recommendations || '',
                    parts_by: inspData.parts_by || 'SERVICE'
                });
            }

            // 3. Fetch Existing Quote
            const { data: qData } = await supabase
                .from('quotes')
                .select('*, quote_items(*)')
                .eq('request_id', requestId)
                .maybeSingle();

            if (qData) {
                setExistingQuote(qData);
                setQuoteItems(qData.quote_items || []);
                setEta({
                    hours_min: qData.eta_hours_min || 2,
                    hours_max: qData.eta_hours_max || 4,
                    notes: qData.eta_notes || ''
                });
            }

            // 3. Fetch Standard Checklist Template items (for generation)
            const { data: items } = await supabase
                .from('checklist_items')
                .select('*')
                .order('order_index', { ascending: true });
            setChecklistItems(items || []);

        } catch (err: any) {
            console.error('Error loading detail:', err);
            toast({ title: 'Error', description: 'No se pudo cargar la información.', type: 'error' });
        } finally {
            setLoading(false);
        }
    }

    async function generateChecklist() {
        if (!user || !requestId || checklistItems.length === 0) return;
        setLoading(true);
        try {
            // Create Inspection
            const { data: newInsp, error: inspError } = await supabase
                .from('inspections')
                .insert({
                    request_id: requestId,
                    tech_user_id: user.id,
                    status: 'DRAFT'
                })
                .select()
                .single();

            if (inspError) throw inspError;

            // Create Initial Results
            const initialResults = checklistItems.map(item => ({
                inspection_id: newInsp.id,
                item_id: item.id,
                status: 'PENDING'
            }));

            const { error: resError } = await supabase
                .from('inspection_results')
                .insert(initialResults);

            if (resError) throw resError;

            toast({ title: 'Checklist Generado', description: 'Puedes comenzar la inspección.', type: 'success' });
            loadData();
        } catch (err: any) {
            console.error('Error generating checklist:', err);
            toast({ title: 'Error', description: 'No se pudo generar el checklist.', type: 'error' });
        } finally {
            setLoading(false);
        }
    }

    async function updateResult(resultId: string, updates: any) {
        try {
            const { error } = await supabase
                .from('inspection_results')
                .update(updates)
                .eq('id', resultId);
            if (error) throw error;

            // Local update
            setResults(prev => prev.map(r => r.id === resultId ? { ...r, ...updates } : r));
        } catch (err: any) {
            toast({ title: 'Error al guardar', type: 'error' });
        }
    }

    async function handleFileUpload(e: React.ChangeEvent<HTMLInputElement>, resultId: string) {
        const file = e.target.files?.[0];
        if (!file || !user) return;

        setUploading(true);
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `${requestId}/${resultId}_${Math.random()}.${fileExt}`;
            const filePath = `${fileName}`;

            const { error: uploadError } = await supabase.storage
                .from('attachments')
                .upload(filePath, file);

            if (uploadError) throw uploadError;

            const { data: { publicUrl } } = supabase.storage
                .from('attachments')
                .getPublicUrl(filePath);

            const result = results.find(r => r.id === resultId);
            const currentPhotos = result.photo_urls || [];
            await updateResult(resultId, { photo_urls: [...currentPhotos, publicUrl] });

            toast({ title: 'Imagen subida', type: 'success' });
        } catch (err: any) {
            console.error('Upload error:', err);
            toast({ title: 'Error de carga', description: 'No se pudo subir la imagen.', type: 'error' });
        } finally {
            setUploading(false);
        }
    }

    async function finishInspection() {
        if (!inspection) return;
        setLoading(true);
        try {
            const htmlSnapshot = `
                <div style="font-family: sans-serif; max-width: 800px; margin: auto; padding: 20px; color: #334155;">
                    <h1 style="color: #2563eb;">Informe de Inspección Digital</h1>
                    <div style="display: flex; gap: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 15px; margin-bottom: 20px;">
                        <div><strong>Vehículo:</strong> ${request?.vehicles?.make} ${request?.vehicles?.model}</div>
                        <div><strong>Riesgo:</strong> ${diagnosis.risk}</div>
                        <div><strong>Fecha:</strong> ${new Date().toLocaleDateString()}</div>
                    </div>
                    
                    <h2 style="font-size: 1.1em; color: #1e293b;">Hallazgos Principales</h2>
                    <p style="background: #f8fafc; padding: 15px; border-radius: 8px;">${diagnosis.findings || 'Sin hallazgos reportados.'}</p>
                    
                    <h2 style="font-size: 1.1em; color: #1e293b; margin-top: 20px;">Recomendación & Plan</h2>
                    <p style="background: #f1f5f9; padding: 15px; border-radius: 8px;">${diagnosis.recommendations || 'Sin recomendaciones reportadas.'}</p>
                    
                    <h2 style="font-size: 1.1em; color: #1e293b; margin-top: 20px;">Checklist</h2>
                    ${results.map(r => `
                        <div style="display: flex; justify-content: space-between; padding: 8px 0; border-bottom: 1px solid #f1f5f9;">
                            <span>${r.checklist_items?.item_name}</span>
                            <span style="font-weight: bold; color: ${r.status === 'OK' ? '#10b981' : r.status === 'ISSUE' ? '#ef4444' : '#64748b'}">${r.status}</span>
                        </div>
                    `).join('')}
                </div>
            `;

            // 1. Update Inspection with Diagnosis
            const { error: inspError } = await supabase
                .from('inspections')
                .update({
                    status: 'COMPLETED',
                    html_snapshot: htmlSnapshot,
                    risk: diagnosis.risk,
                    findings: diagnosis.findings,
                    recommendations: diagnosis.recommendations,
                    parts_by: diagnosis.parts_by
                })
                .eq('id', inspection.id);

            if (inspError) throw inspError;

            // 2. Update Request Status to DIAGNOSED
            const { error: reqError } = await supabase
                .from('service_requests')
                .update({ status: 'DIAGNOSED' })
                .eq('id', requestId);

            if (reqError) throw reqError;

            // 3. Enqueue Notification
            await supabase.from('notifications_outbox').insert({
                recipient_user_id: request.customer_user_id,
                recipient: request.profiles?.email || request.profiles?.phone || '',
                channel: request.profiles?.preferred_channel || 'EMAIL',
                template_code: 'DIAGNOSIS_READY',
                payload: {
                    data: {
                        name: request.profiles?.first_name || 'Cliente',
                        vehicle: `${request?.vehicles?.make} ${request?.vehicles?.model}`
                    }
                },
                status: 'PENDING'
            });

            // 4. Audit Log
            await supabase.from('audit_logs').insert({
                action: 'INSPECTION_COMPLETED',
                entity_type: 'service_request',
                entity_id: requestId,
                actor_user_id: user?.id,
                new_data: { status: 'DIAGNOSED', diagnosis: diagnosis }
            });

            toast({ title: 'Diagnóstico Finalizado', description: 'El reporte ha sido enviado al cliente.', type: 'success' });
            navigate('/tech/requests');
        } catch (err: any) {
            console.error('Error saving diagnosis:', err);
            toast({ title: 'Error', description: 'No se pudo guardar el diagnóstico.', type: 'error' });
        } finally {
            setLoading(false);
        }
    }

    const downloadChecklist = () => {
        const html = `
            <html>
                <head>
                    <title>Reporte de Inspección - ${request?.vehicles?.make} ${request?.vehicles?.model}</title>
                    <style>
                        body { font-family: sans-serif; padding: 40px; }
                        h1 { color: #2563eb; }
                        .section { margin-bottom: 20px; border-bottom: 1px solid #eee; padding-bottom: 10px; }
                        .item { display: flex; justify-content: space-between; margin-bottom: 5px; }
                        .status { font-weight: bold; }
                        .OK { color: green; } .ISSUE { color: red; } .NA { color: gray; }
                    </style>
                </head>
                <body>
                    <h1>Denver Mobile Auto Care - Reporte de Inspección</h1>
                    <p><strong>Cliente:</strong> ${request?.profiles?.first_name} ${request?.profiles?.last_name}</p>
                    <p><strong>Vehículo:</strong> ${request?.vehicles?.year} ${request?.vehicles?.make} ${request?.vehicles?.model}</p>
                    <p><strong>Fecha:</strong> ${new Date().toLocaleDateString()}</p>
                    <hr/>
                    ${results.map(r => `
                        <div class="item">
                            <span>[${r.checklist_items?.category}] ${r.checklist_items?.item_name}</span>
                            <span class="status ${r.status}">${r.status}</span>
                        </div>
                    `).join('')}
                </body>
            </html>
        `;
        const blob = new Blob([html], { type: 'text/html' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `inspeccion_${requestId}.html`;
        a.click();
    };

    if (loading && !request) {
        return <div className="p-10 text-center">Cargando...</div>;
    }

    const addQuoteItem = () => {
        setQuoteItems([...quoteItems, { description: '', quantity: 1, unit_price: 0, type: 'PART' }]);
    };

    const removeQuoteItem = (index: number) => {
        setQuoteItems(quoteItems.filter((_, i) => i !== index));
    };

    const updateQuoteItem = (index: number, updates: any) => {
        const newItems = [...quoteItems];
        newItems[index] = { ...newItems[index], ...updates };
        setQuoteItems(newItems);
    };

    const calculateTotals = () => {
        let labor = 0;
        let parts = 0;
        let discount = 0;

        quoteItems.forEach(item => {
            const total = (item.quantity || 0) * (item.unit_price || 0);
            if (item.type === 'LABOR') labor += total;
            else if (item.type === 'PART') parts += total;
            else if (item.type === 'DISCOUNT') discount += total;
        });

        return { labor, parts, discount, total: labor + parts - Math.abs(discount) };
    };

    async function sendQuote() {
        if (!requestId || quoteItems.length === 0) return;
        setLoading(true);
        try {
            const totals = calculateTotals();

            // 1. Create or Update Quote
            const { data: qData, error: qError } = await supabase
                .from('quotes')
                .upsert({
                    id: existingQuote?.id,
                    request_id: requestId,
                    status: 'SENT',
                    eta_hours_min: eta.hours_min,
                    eta_hours_max: eta.hours_max,
                    eta_notes: eta.notes,
                    total_parts: totals.parts,
                    total_labor: totals.labor,
                    grand_total: totals.total
                })
                .select()
                .single();

            if (qError) throw qError;

            // 2. Insert Items (Delete existing if update)
            if (existingQuote) {
                await supabase.from('quote_items').delete().eq('quote_id', existingQuote.id);
            }

            const itemsToInsert = quoteItems.map(item => ({
                quote_id: qData.id,
                type: item.type,
                description: item.description,
                quantity: item.quantity,
                unit_price: item.unit_price,
                total_price: item.quantity * item.unit_price
            }));

            const { error: itemsError } = await supabase.from('quote_items').insert(itemsToInsert);
            if (itemsError) throw itemsError;

            // 3. Update Request Status
            await supabase.from('service_requests').update({ status: 'QUOTED' }).eq('id', requestId);

            // 4. Notification
            await supabase.from('notifications_outbox').insert({
                recipient_user_id: request.customer_user_id,
                recipient: request.profiles?.email || request.profiles?.phone || '',
                channel: request.profiles?.preferred_channel || 'EMAIL',
                template_code: 'QUOTE_SENT',
                payload: {
                    data: {
                        name: request.profiles?.first_name || 'Cliente',
                        vehicle: `${request?.vehicles?.make} ${request?.vehicles?.model}`
                    }
                },
                status: 'PENDING'
            });

            toast({ title: 'Cotización Enviada', type: 'success' });
            loadData();
        } catch (err: any) {
            console.error('Error sending quote:', err);
            toast({ title: 'Error', description: 'No se pudo enviar la cotización.', type: 'error' });
        } finally {
            setLoading(false);
        }
    }

    // Group results by category
    const categories = Array.from(new Set(results.map(r => r.checklist_items?.category)));

    return (
        <div className="max-w-6xl mx-auto space-y-6 animate-in pb-20">
            <Link to="/tech/requests" className="inline-flex items-center text-sm text-muted-foreground hover:text-primary transition-colors">
                <ArrowLeft size={16} className="mr-1" /> Volver a agenda
            </Link>

            <div className="flex justify-between items-start flex-wrap gap-4">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <Badge variant="outline">{request?.status}</Badge>
                        <span className="text-xs text-muted-foreground">ID: {requestId?.split('-')[0]}</span>
                    </div>
                    <h1 className="text-2xl font-bold">
                        {request?.vehicles?.make} {request?.vehicles?.model} {request?.vehicles?.year}
                    </h1>
                    <p className="text-muted-foreground">
                        Cliente: <strong>{request?.profiles?.first_name} {request?.profiles?.last_name}</strong> • {request?.profiles?.phone}
                    </p>
                </div>
                <div className="flex gap-2">
                    {inspection ? (
                        <>
                            <Button variant="outline" onClick={downloadChecklist}>
                                <Printer size={16} className="mr-2" /> Reporte
                            </Button>
                            <Button onClick={finishInspection} disabled={results.some(r => r.status === 'PENDING')}>
                                Finalizar Inspección
                            </Button>
                        </>
                    ) : (
                        <Button onClick={generateChecklist} variant="primary">
                            <FileText size={16} className="mr-2" /> Generar Checklist
                        </Button>
                    )}
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Information Card */}
                <Card className="lg:col-span-1">
                    <CardHeader>
                        <CardTitle className="text-sm uppercase tracking-wider text-muted-foreground">Información del Caso</CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div>
                            <p className="text-xs font-bold text-slate-400">MOTIVO / SERVICIO SOLICITADO</p>
                            <p className="text-sm font-medium">{request?.service_catalog?.name}</p>
                        </div>
                        <div>
                            <p className="text-xs font-bold text-slate-400">SÍNTOMAS REPORTADOS</p>
                            <div className="flex flex-wrap gap-1 mt-1">
                                {request?.request_symptoms?.map((s: any) => (
                                    <Badge key={s.symptom_tags.id} variant="secondary" className="text-[10px]">
                                        {s.symptom_tags.label}
                                    </Badge>
                                ))}
                            </div>
                            <p className="text-sm mt-2 italic text-slate-600">"{request?.symptoms_free_text || 'Sin notas adicionales'}"</p>
                        </div>
                        {request?.triage_risk && (
                            <div className={`p-3 rounded-lg border flex items-center gap-3 ${request.triage_risk === 'HIGH' ? 'bg-red-50 border-red-100 text-red-700' : 'bg-amber-50 border-amber-100 text-amber-700'}`}>
                                <AlertTriangle size={20} />
                                <div>
                                    <p className="text-xs font-bold">TRIAGE: {request.triage_risk}</p>
                                    <p className="text-[10px]">{request.triage_notes}</p>
                                </div>
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* Inspection Area */}
                <div className="lg:col-span-2 space-y-6">
                    {!inspection ? (
                        <div className="bg-muted/50 border-2 border-dashed border-border rounded-xl p-12 text-center flex flex-col items-center justify-center">
                            <CheckSquare size={48} className="text-muted-foreground mb-4 opacity-20" />
                            <h3 className="text-lg font-medium">No se ha iniciado la inspección</h3>
                            <p className="text-sm text-muted-foreground mt-2 max-w-xs mx-auto">
                                Haz clic en "Generar Checklist" para cargar los puntos de revisión estándar para este vehículo.
                            </p>
                        </div>
                    ) : (
                        <div className="space-y-8">
                            {categories.map(cat => (
                                <div key={cat} className="space-y-3">
                                    <h3 className="text-sm font-bold text-primary flex items-center gap-2">
                                        <div className="w-1 h-4 bg-primary rounded-full" />
                                        {cat}
                                    </h3>
                                    <div className="grid grid-cols-1 gap-3">
                                        {results.filter(r => r.checklist_items?.category === cat).map(r => (
                                            <Card key={r.id} className={`overflow-hidden border-l-4 ${r.status === 'OK' ? 'border-l-success' : r.status === 'ISSUE' ? 'border-l-destructive' : 'border-l-slate-300'}`}>
                                                <CardContent className="p-4">
                                                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                                        <div className="flex-1">
                                                            <p className="text-sm font-bold">{r.checklist_items?.item_name}</p>
                                                            <div className="mt-2 text-xs flex gap-2">
                                                                <button
                                                                    onClick={() => updateResult(r.id, { status: 'OK' })}
                                                                    className={`px-3 py-1 rounded-full flex items-center gap-1 transition-colors ${r.status === 'OK' ? 'bg-success text-white' : 'bg-slate-100 text-slate-500 hover:bg-success/10'}`}
                                                                >
                                                                    <CheckCircle2 size={12} /> OK
                                                                </button>
                                                                <button
                                                                    onClick={() => updateResult(r.id, { status: 'ISSUE' })}
                                                                    className={`px-3 py-1 rounded-full flex items-center gap-1 transition-colors ${r.status === 'ISSUE' ? 'bg-destructive text-white' : 'bg-slate-100 text-slate-500 hover:bg-destructive/10'}`}
                                                                >
                                                                    <AlertTriangle size={12} /> FALLA
                                                                </button>
                                                                <button
                                                                    onClick={() => updateResult(r.id, { status: 'NA' })}
                                                                    className={`px-3 py-1 rounded-full flex items-center gap-1 transition-colors ${r.status === 'NA' ? 'bg-slate-600 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
                                                                >
                                                                    <MinusCircle size={12} /> N/A
                                                                </button>
                                                            </div>
                                                        </div>
                                                        <div className="w-full md:w-auto flex items-center gap-2">
                                                            <div className="relative group">
                                                                <Button
                                                                    variant="ghost"
                                                                    size="icon"
                                                                    className={`h-8 w-8 text-muted-foreground ${uploading ? 'animate-pulse opacity-50' : ''}`}
                                                                    disabled={uploading}
                                                                    onClick={() => fileInputRef.current?.click()}
                                                                >
                                                                    <UploadCloud size={16} />
                                                                </Button>
                                                                <input
                                                                    type="file"
                                                                    ref={fileInputRef}
                                                                    className="hidden"
                                                                    accept="image/*"
                                                                    onChange={(e) => handleFileUpload(e, r.id)}
                                                                />
                                                            </div>
                                                            <Input
                                                                placeholder="Notas..."
                                                                className="h-8 text-xs"
                                                                value={r.notes || ''}
                                                                onChange={(e) => setResults(prev => prev.map(item => item.id === r.id ? { ...item, notes: e.target.value } : item))}
                                                                onBlur={(e) => updateResult(r.id, { notes: e.target.value })}
                                                            />
                                                            <Button
                                                                variant="ghost"
                                                                size="icon"
                                                                className="h-8 w-8"
                                                                onClick={() => updateResult(r.id, { notes: r.notes })}
                                                            >
                                                                <Save size={14} className="text-primary" />
                                                            </Button>
                                                        </div>
                                                    </div>
                                                    {r.photo_urls && r.photo_urls.length > 0 && (
                                                        <div className="flex gap-2 mt-3 overflow-x-auto pb-1">
                                                            {r.photo_urls.map((url: string, i: number) => (
                                                                <img key={i} src={url} className="h-16 w-16 object-cover rounded-md border" />
                                                            ))}
                                                        </div>
                                                    )}
                                                </CardContent>
                                            </Card>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* Diagnosis Module */}
                    {inspection && (
                        <Card className="mt-8 border-primary bg-primary/5">
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2">
                                    <FileText size={20} className="text-primary" />
                                    Diagnóstico Técnico & Plan
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-6">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <label className="text-sm font-bold">Nivel de Riesgo (Risk)</label>
                                        <div className="flex gap-2">
                                            {['LOW', 'MED', 'HIGH'].map(r => (
                                                <button
                                                    key={r}
                                                    onClick={() => setDiagnosis({ ...diagnosis, risk: r })}
                                                    className={`flex-1 py-2 px-3 rounded-md border text-sm font-bold transition-all ${diagnosis.risk === r
                                                        ? r === 'HIGH' ? 'bg-destructive text-white border-destructive'
                                                            : r === 'MED' ? 'bg-amber-500 text-white border-amber-500'
                                                                : 'bg-success text-white border-success'
                                                        : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}
                                                >
                                                    {r}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-sm font-bold">Suministro de Refacciones</label>
                                        <select
                                            className="w-full h-10 px-3 rounded-md border border-slate-200 text-sm focus:ring-2 focus:ring-primary/20 outline-none"
                                            value={diagnosis.parts_by}
                                            onChange={(e) => setDiagnosis({ ...diagnosis, parts_by: e.target.value })}
                                        >
                                            <option value="SERVICE">Nosotros proveemos todo</option>
                                            <option value="CUSTOMER">El cliente provee todo</option>
                                            <option value="MIXED">Mixto (Algunas piezas el cliente)</option>
                                        </select>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <label className="text-sm font-bold">Hallazgos (Findings)</label>
                                    <textarea
                                        className="w-full min-h-[100px] p-4 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-primary/20 outline-none"
                                        placeholder="Describe lo que encontraste (fugas, desgaste, códigos de falla...)"
                                        value={diagnosis.findings}
                                        onChange={(e) => setDiagnosis({ ...diagnosis, findings: e.target.value })}
                                    />
                                </div>

                                <div className="space-y-2">
                                    <label className="text-sm font-bold">Recomendaciones & Plan de Acción</label>
                                    <textarea
                                        className="w-full min-h-[100px] p-4 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-primary/20 outline-none"
                                        placeholder="¿Qué sugieres hacer? (Ej: Cambio de balatas delanteras y rectificado)"
                                        value={diagnosis.recommendations}
                                        onChange={(e) => setDiagnosis({ ...diagnosis, recommendations: e.target.value })}
                                    />
                                </div>
                            </CardContent>
                            <CardContent className="bg-slate-50 border-t flex justify-end p-4">
                                <Button
                                    onClick={finishInspection}
                                    className="w-full md:w-auto"
                                    disabled={loading || results.some(r => r.status === 'PENDING') || !diagnosis.findings || !diagnosis.recommendations}
                                >
                                    {diagnosis.risk === 'HIGH' && <AlertTriangle size={16} className="mr-2" />}
                                    Finalizar & Notificar Cliente
                                </Button>
                            </CardContent>
                        </Card>
                    )}

                    {/* Quoting Module */}
                    <Card className="mt-8">
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <DollarSign size={20} className="text-primary" />
                                Cotización & Presupuesto
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            {/* ETA Section */}
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 p-4 bg-muted/30 rounded-lg">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-muted-foreground uppercase">ETA MIN (Hrs)</label>
                                    <Input type="number" value={eta.hours_min} onChange={e => setEta({ ...eta, hours_min: parseInt(e.target.value) })} />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-muted-foreground uppercase">ETA MAX (Hrs)</label>
                                    <Input type="number" value={eta.hours_max} onChange={e => setEta({ ...eta, hours_max: parseInt(e.target.value) })} />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-muted-foreground uppercase">Notas de Tiempo</label>
                                    <Input placeholder="Ej: Sujeto a disponibilidad de partes" value={eta.notes} onChange={e => setEta({ ...eta, notes: e.target.value })} />
                                </div>
                            </div>

                            {/* Items List */}
                            <div className="space-y-3">
                                <div className="flex justify-between items-center">
                                    <h4 className="text-sm font-bold">Conceptos de Cobro</h4>
                                    <Button size="sm" variant="outline" onClick={addQuoteItem}>+ Agregar Item</Button>
                                </div>
                                <div className="border rounded-lg divide-y overflow-hidden">
                                    {quoteItems.length === 0 && (
                                        <div className="p-8 text-center text-muted-foreground text-sm">
                                            No hay conceptos agregados. Agrega mano de obra o refacciones.
                                        </div>
                                    )}
                                    {quoteItems.map((item, idx) => (
                                        <div key={idx} className="p-4 flex flex-wrap md:flex-nowrap gap-4 items-end bg-white">
                                            <div className="w-full md:w-32">
                                                <label className="text-[10px] font-bold">TIPO</label>
                                                <select
                                                    className="w-full h-10 px-2 rounded-md border text-sm"
                                                    value={item.type}
                                                    onChange={e => updateQuoteItem(idx, { type: e.target.value })}
                                                >
                                                    <option value="LABOR">Mano de Obra</option>
                                                    <option value="PART">Refacción</option>
                                                    <option value="FEE">Cargo Extra</option>
                                                    <option value="DISCOUNT">Descuento</option>
                                                </select>
                                            </div>
                                            <div className="flex-1 min-w-[200px]">
                                                <label className="text-[10px] font-bold">DESCRIPCIÓN</label>
                                                <Input value={item.description} onChange={e => updateQuoteItem(idx, { description: e.target.value })} />
                                            </div>
                                            <div className="w-20">
                                                <label className="text-[10px] font-bold">CANT</label>
                                                <Input type="number" value={item.quantity} onChange={e => updateQuoteItem(idx, { quantity: parseFloat(e.target.value) })} />
                                            </div>
                                            <div className="w-28">
                                                <label className="text-[10px] font-bold">PRECIO U.</label>
                                                <Input type="number" value={item.unit_price} onChange={e => updateQuoteItem(idx, { unit_price: parseFloat(e.target.value) })} />
                                            </div>
                                            <Button variant="ghost" size="icon" className="text-destructive mb-1" onClick={() => removeQuoteItem(idx)}>
                                                <MinusCircle size={18} />
                                            </Button>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* Totals Summary */}
                            <div className="flex flex-col items-end pt-4 space-y-2">
                                <div className="w-full max-w-xs space-y-1">
                                    <div className="flex justify-between text-sm">
                                        <span className="text-muted-foreground">Subtotal Labor:</span>
                                        <span className="font-medium">${calculateTotals().labor.toFixed(2)}</span>
                                    </div>
                                    <div className="flex justify-between text-sm">
                                        <span className="text-muted-foreground">Subtotal Partes:</span>
                                        <span className="font-medium">${calculateTotals().parts.toFixed(2)}</span>
                                    </div>
                                    {calculateTotals().discount > 0 && (
                                        <div className="flex justify-between text-sm text-success">
                                            <span>Descuentos:</span>
                                            <span>-${calculateTotals().discount.toFixed(2)}</span>
                                        </div>
                                    )}
                                    <div className="flex justify-between text-lg font-bold border-t pt-2 mt-2 text-primary">
                                        <span>Total Estimado:</span>
                                        <span>${calculateTotals().total.toFixed(2)}</span>
                                    </div>
                                </div>
                            </div>
                        </CardContent>
                        <CardFooter className="bg-slate-50 flex justify-between items-center p-6 border-t">
                            <div className="flex gap-2">
                                <Button variant="outline" onClick={() => setQuoteItems([...quoteItems, { type: 'DISCOUNT', description: 'Cortesía Visit Fee', quantity: 1, unit_price: 30 }])}>
                                    Aplicar Descuento Visita (-$30)
                                </Button>
                            </div>
                            <Button onClick={sendQuote} disabled={loading || quoteItems.length === 0} className="min-w-[200px]">
                                Enviar Cotización al Cliente
                            </Button>
                        </CardFooter>
                    </Card>
                </div>

            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { Badge } from '../../components/ui/Badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../../components/ui/Table';
import { Link } from 'react-router-dom';
import { Button } from '../../components/ui/Button';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../contexts/AuthContext';
import { useToast } from '../../components/ui/Toast';
import { Calendar, MapPin, Wrench, User } from 'lucide-react';

export function TechRequestsPage() {
    const { user } = useAuth();
    const { toast } = useToast();
    const [myAppointments, setMyAppointments] = useState<any[]>([]);
    const [availableAppointments, setAvailableAppointments] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    const loadAppointments = async () => {
        if (!user) return;
        setLoading(true);
        try {
            // My Assigned Appointments
            const { data: assigned, error: assignedError } = await supabase
                .from('appointments')
                .select('*, service_requests(*, profiles(*), vehicles(*), service_catalog(*))')
                .eq('assigned_tech_user_id', user.id)
                .order('scheduled_start', { ascending: true });

            if (assignedError) throw assignedError;
            setMyAppointments(assigned || []);

            // Unassigned Appointments
            const { data: unassigned, error: unassignedError } = await supabase
                .from('appointments')
                .select('*, service_requests(*, profiles(*), vehicles(*), service_catalog(*))')
                .is('assigned_tech_user_id', null)
                .neq('status', 'CANCELED')
                .order('scheduled_start', { ascending: true });

            if (unassignedError) throw unassignedError;
            setAvailableAppointments(unassigned || []);

        } catch (err: any) {
            console.error('Error loading tech requests:', err);
            toast({ title: 'Error', description: 'No se pudieron cargar los servicios.', type: 'error' });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadAppointments();
    }, [user]);

    const handleClaim = async (apptId: string) => {
        try {
            const { error } = await supabase
                .from('appointments')
                .update({
                    assigned_tech_user_id: user?.id,
                    status: 'SCHEDULED'
                })
                .eq('id', apptId);

            if (error) throw error;

            toast({ title: 'Servicio Asignado', description: 'Has tomado la responsabilidad de este servicio.', type: 'success' });
            loadAppointments();
        } catch (err: any) {
            console.error('Error claiming appointment:', err);
            toast({ title: 'Error', description: 'No se pudo tomar el servicio.', type: 'error' });
        }
    };

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[50vh] gap-4">
                <div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <p className="text-muted-foreground">Cargando servicios...</p>
            </div>
        );
    }

    return (
        <div className="space-y-10 animate-in">
            {/* My Active Work */}
            <section className="space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold">Mis Servicios Asignados</h1>
                        <p className="text-muted-foreground">Visitas que tienes programadas.</p>
                    </div>
                </div>

                <Card>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Fecha/Hora</TableHead>
                                <TableHead>Cliente & Vehículo</TableHead>
                                <TableHead>Servicio</TableHead>
                                <TableHead>Ubicación</TableHead>
                                <TableHead>Estado</TableHead>
                                <TableHead></TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {myAppointments.length === 0 ? (
                                <TableRow>
                                    <TableCell colSpan={6} className="text-center py-10 text-muted-foreground">
                                        No tienes servicios asignados actualmente.
                                    </TableCell>
                                </TableRow>
                            ) : (
                                myAppointments.map((appt) => (
                                    <TableRow key={appt.id}>
                                        <TableCell className="font-medium whitespace-nowrap">
                                            <div className="flex flex-col">
                                                <span>{new Date(appt.scheduled_start).toLocaleDateString()}</span>
                                                <span className="text-xs text-muted-foreground">
                                                    {new Date(appt.scheduled_start).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                                </span>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <div className="flex flex-col">
                                                <span className="font-medium">{appt.service_requests?.profiles?.first_name} {appt.service_requests?.profiles?.last_name}</span>
                                                <span className="text-xs text-muted-foreground">
                                                    {appt.service_requests?.vehicles?.year} {appt.service_requests?.vehicles?.make} {appt.service_requests?.vehicles?.model}
                                                </span>
                                            </div>
                                        </TableCell>
                                        <TableCell>{appt.service_requests?.service_catalog?.name || 'Diagnóstico'}</TableCell>
                                        <TableCell>
                                            <div className="flex items-center gap-1 text-xs max-w-[150px] truncate">
                                                <MapPin size={12} className="shrink-0" />
                                                {appt.address}
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <Badge variant={appt.status === 'COMPLETED' ? 'success' : 'warning'}>
                                                {appt.status.toUpperCase()}
                                            </Badge>
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <Link to={`/tech/requests/${appt.request_id}`}>
                                                <Button size="sm">Trabajar</Button>
                                            </Link>
                                        </TableCell>
                                    </TableRow>
                                ))
                            )}
                        </TableBody>
                    </Table>
                </Card>
            </section>

            {/* Available Work */}
            <section className="space-y-6">
                <div>
                    <h2 className="text-xl font-bold">Servicios Disponibles</h2>
                    <p className="text-muted-foreground">Solicitudes que aún no tienen un técnico asignado.</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {availableAppointments.length === 0 ? (
                        <p className="text-muted-foreground italic col-span-full">No hay servicios nuevos para tomar en este momento.</p>
                    ) : (
                        availableAppointments.map((appt) => (
                            <Card key={appt.id} className="hover:border-primary transition-colors">
                                <CardHeader className="pb-2">
                                    <div className="flex justify-between items-start mb-2">
                                        <Badge variant="outline" className="bg-primary/5 text-primary">NUEVA SOLICITUD</Badge>
                                        <span className="text-xs font-bold">${appt.total_visit_cost}</span>
                                    </div>
                                    <CardTitle className="text-lg">
                                        {appt.service_requests?.service_catalog?.name || 'Diagnóstico General'}
                                    </CardTitle>
                                    <div className="text-sm text-muted-foreground flex items-center gap-1">
                                        <User size={14} />
                                        {appt.service_requests?.profiles?.first_name} {appt.service_requests?.profiles?.last_name}
                                    </div>
                                </CardHeader>
                                <CardContent className="space-y-4 text-sm">
                                    <div className="space-y-2 py-2 border-y border-slate-50">
                                        <div className="flex items-center gap-2">
                                            <Calendar size={14} className="text-slate-400" />
                                            <span>{new Date(appt.scheduled_start).toLocaleDateString()} @ {new Date(appt.scheduled_start).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <MapPin size={14} className="text-slate-400" />
                                            <span className="truncate">{appt.city}, {appt.zip}</span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Wrench size={14} className="text-slate-400" />
                                            <span>{appt.service_requests?.vehicles?.make} {appt.service_requests?.vehicles?.model}</span>
                                        </div>
                                    </div>
                                    <Button className="w-full" variant="outline" onClick={() => handleClaim(appt.id)}>
                                        Tomar Asignación
                                    </Button>
                                </CardContent>
                            </Card>
                        ))
                    )}
                </div>
            </section>
        </div>
    );
}
